// it generated the CSV procedurally rather than embedding a
// literal payload like every other tool.)

// ── Axis ticks ───────────────────────────────────────────────────────────────

function niceStep(range, approxN) {
  const rough = range / approxN;
  const mag = Math.pow(10, Math.floor(Math.log10(rough)));
  const nice = rough / mag;
  if (nice <= 1) return mag;
  if (nice <= 2) return 2 * mag;
  if (nice <= 5) return 5 * mag;
  return 10 * mag;
}
function makeTicks(min, max, approxN) {
  const step = niceStep(max - min || 1, approxN);
  const start = Math.ceil(min / step) * step;
  const ticks = [];
  for (let v = start; v <= max + step * 0.001; v += step) {
    const tick = parseFloat(v.toPrecision(10));
    if (tick <= max + step * 1e-9) ticks.push(tick);
  }
  return ticks;
}
function makeLogTicks(dataMin, dataMax, base) {
  if (!isFinite(dataMin) || dataMin <= 0) dataMin = base === 2 ? 0.5 : 0.1;
  if (!isFinite(dataMax) || dataMax <= dataMin) dataMax = dataMin * 1000;
  const logFn = base === 2 ? Math.log2 : base === 10 ? Math.log10 : Math.log;
  const logMin = Math.floor(logFn(dataMin));
  const logMax = Math.ceil(logFn(dataMax));
  const decades = logMax - logMin;
  const ticks = [];
  for (let exp = logMin; exp <= logMax; exp++) {
    const v = Math.pow(base, exp);
    if (v >= dataMin * 0.99 && v <= dataMax * 1.01) ticks.push({ value: v, major: true });
    if (base === 10) {
      const muls = [2, 3, 4, 5, 6, 7, 8, 9];
      for (const mul of muls) {
        const sv = mul * Math.pow(base, exp);
        if (sv >= dataMin * 0.99 && sv <= dataMax * 1.01) ticks.push({ value: sv, major: false });
      }
    } else if (base === 2 && decades <= 8) {
      const mid = Math.pow(base, exp) * 1.5;
      if (mid >= dataMin * 0.99 && mid <= dataMax * 1.01) ticks.push({ value: mid, major: false });
    }
  }
  ticks.sort((a, b) => a.value - b.value);
  return ticks;
}

// ── Separator detection ───────────────────────────────────────────────────────
//
// Picks the delimiter most likely to produce a consistent column count. The
// naive "count occurrences across the first 2 kB" heuristic fails on TSVs
// whose header has commas in free-text ("Sample, Description, Notes") — those
// header-level commas can out-count the tabs in data rows and flip the
// detection to `,`, collapsing 20 data columns to 1.
//
// Strategy: for each candidate (`\t`, `;`, `,`), measure how uniform the
// per-line count is across the first ~50 non-empty lines. A real delimiter
// partitions every line into the SAME number of columns, so its per-line
// count has low variance and a median ≥ 1. A separator that sneaks into
// quoted text or headers only produces inconsistent per-line counts.
//
// Ranking key: (medianPerLine >= 1, then low coefficient of variation, then
// high total count). Falls back to `\s+` only when no candidate appears at
// all.
function autoDetectSep(text, override = "") {
  if (override !== "") return override;
  const h = text.slice(0, 2000);
  // Bound the scan to ~50 non-empty lines — enough to see pattern, cheap.
  const lines = h.split(/\r?\n/).filter((l) => l.trim() !== "");
  const head = lines.slice(0, Math.min(50, lines.length));
  if (head.length === 0) return /\s+/;

  const CANDIDATES = ["\t", ";", ","];
  const scores = CANDIDATES.map((sep) => {
    const countPerLine = head.map((line) => {
      // Quoted-field-aware count: skip chars inside "..." (matches the
      // tokenizer so the detector can't be fooled by an inlined delimiter
      // in a legitimately-quoted cell).
      let n = 0;
      let inQuoted = false;
      for (let i = 0; i < line.length; i++) {
        const ch = line[i];
        if (ch === '"') {
          inQuoted = !inQuoted;
          continue;
        }
        if (!inQuoted && ch === sep) n++;
      }
      return n;
    });
    const total = countPerLine.reduce((a, b) => a + b, 0);
    const sorted = countPerLine.slice().sort((a, b) => a - b);
    const median = sorted[Math.floor(sorted.length / 2)];
    const mean = total / countPerLine.length;
    // Sample variance with Bessel correction collapses to 0 for uniform
    // counts; coefficient of variation is σ / μ (0 when perfectly uniform).
    let variance = 0;
    if (countPerLine.length > 1) {
      for (const n of countPerLine) variance += (n - mean) * (n - mean);
      variance /= countPerLine.length - 1;
    }
    const cv = mean > 0 ? Math.sqrt(variance) / mean : Infinity;
    return { sep, total, median, cv };
  });

  // Keep only candidates that actually show up in most lines. A separator
  // with median 0 never partitions more than half the lines → it's noise.
  const viable = scores.filter((s) => s.median >= 1);
  if (viable.length === 0) {
    // No candidate partitions consistently — fall back to "highest raw count"
    // like the old heuristic, or to whitespace when nothing appears.
    const best = scores.reduce((a, b) => (b.total > a.total ? b : a));
    return best.total === 0 ? /\s+/ : best.sep;
  }
  // Prefer the most-uniform partition (lowest CV). Break ties by total count.
  viable.sort((a, b) => a.cv - b.cv || b.total - a.total);
  return viable[0].sep;
}

// ── Delimited-text tokenizer ──────────────────────────────────────────────────
//
// RFC 4180-style state machine. Handles quoted fields with embedded separators,
// embedded `\n` / `\r\n` inside quoted cells, escaped `""` pairs, a leading BOM,
// and mixed CRLF/LF line endings. A `"` in the middle of an unquoted field is
// preserved literally (so `5"` as an inch measurement survives) — only a
// leading `"` at the start of a field opens a quoted run.
//
// Cells are post-trimmed to match the historical pre-state-machine behaviour.
// `sep` may be a single-character string (`,`, `\t`, `;`) or a RegExp (only
// used for the `autoDetectSep` whitespace fallback). For the RegExp path we
// fall back to simple line-by-line `split(sep)` because quoted fields don't
// make sense under an arbitrary-whitespace grammar.
function tokenizeDelimited(text, sep) {
  if (typeof text !== "string" || text.length === 0) return [];
  if (text.charCodeAt(0) === 0xfeff) text = text.slice(1);
  // Identify whitespace-fallback regex by duck-typing (an `instanceof RegExp`
  // check would fail under the vm-context loader used by the tests because the
  // regex is constructed in a different realm).
  if (typeof sep !== "string") {
    return text
      .split(/\r?\n/)
      .filter((l) => l.trim() !== "")
      .map((l) => l.trim().split(sep));
  }
  const rows = [];
  let row = [];
  let field = "";
  let inQuoted = false;
  let fieldStarted = false;
  const flushRow = () => {
    row.push(field);
    if (!(row.length === 1 && row[0] === "")) {
      for (let c = 0; c < row.length; c++) row[c] = row[c].trim();
      rows.push(row);
    }
    row = [];
    field = "";
    fieldStarted = false;
  };
  const n = text.length;
  let i = 0;
  while (i < n) {
    const ch = text[i];
    if (inQuoted) {
      if (ch === '"') {
        if (i + 1 < n && text[i + 1] === '"') {
          field += '"';
          i += 2;
        } else {
          inQuoted = false;
          i++;
        }
      } else {
        field += ch;
        i++;
      }
    } else if (!fieldStarted && ch === '"') {
      inQuoted = true;
      fieldStarted = true;
      i++;
    } else if (ch === sep) {
      row.push(field);
      for (let c = 0; c < 0; c++); // no-op; trim happens at flushRow
      field = "";
      fieldStarted = false;
      i++;
    } else if (ch === "\n" || ch === "\r") {
      flushRow();
      if (ch === "\r" && i + 1 < n && text[i + 1] === "\n") i += 2;
      else i++;
    } else {
      field += ch;
      fieldStarted = true;
      i++;
    }
  }
  if (field !== "" || row.length > 0) {
    flushRow();
  }
  // `flushRow` only trims cells when the row wasn't empty; cells in mid-row
  // positions pushed before the row-end still need trimming.
  for (let r = 0; r < rows.length; r++) {
    for (let c = 0; c < rows[r].length; c++) rows[r][c] = rows[r][c].trim();
  }
  return rows;
}

// ── Decimal comma fix (per-column) ────────────────────────────────────────────
//
// Old implementation did a global `/(\d),(\d)/g` text rewrite, which silently
// mangled US-format thousand separators (`1,000.50` → `1.000.50` → NaN) and
// mutated label cells containing commas (`"E,coli"` → `E.coli`).
//
// The new implementation tokenizes the text first, then decides per-column
// whether commas are decimal separators. A column is flagged only when:
//   - it has at least one cell containing a comma,
//   - strictly more cells match `isNumericValue` after `,`→`.` than before,
//   - at least one comma-cell has a non-3-digit fractional part (pure
//     `1,000`/`2,500` patterns look like US thousand groups and are left
//     alone).
// Only flagged columns get rewritten; label columns, mixed-format columns, and
// pure-thousand-grouping columns are preserved exactly.
function fixDecimalCommas(text, sep) {
  if (typeof text !== "string" || text.length === 0) {
    return { text, commaFixed: false, count: 0 };
  }
  if (typeof sep !== "string") return { text, commaFixed: false, count: 0 };
  if (sep === ",") return { text, commaFixed: false, count: 0 };
  if (sep === "") return { text, commaFixed: false, count: 0 };
  const rows = tokenizeDelimited(text, sep);
  if (rows.length < 2) return { text, commaFixed: false, count: 0 };
  const nCols = Math.max(...rows.map((r) => r.length));
  const decimalCommaCols = new Set();
  for (let c = 0; c < nCols; c++) {
    let numericAsIs = 0;
    let numericIfFixed = 0;
    let hasComma = 0;
    let nonEmpty = 0;
    let anyNonThousandish = false;
    for (let r = 1; r < rows.length; r++) {
      const v = rows[r][c];
      if (v == null || v === "") continue;
      nonEmpty++;
      if (v.indexOf(",") !== -1) {
        hasComma++;
        const last = v.lastIndexOf(",");
        const after = v.slice(last + 1);
        const m = after.match(/^\d+/);
        if (!m || m[0].length !== 3) anyNonThousandish = true;
      }
      if (isNumericValue(v)) numericAsIs++;
      if (isNumericValue(v.replace(/,/g, "."))) numericIfFixed++;
    }
    if (nonEmpty > 0 && hasComma > 0 && numericIfFixed > numericAsIs && anyNonThousandish) {
      decimalCommaCols.add(c);
    }
  }
  if (decimalCommaCols.size === 0) return { text, commaFixed: false, count: 0 };
  let count = 0;
  for (let r = 0; r < rows.length; r++) {
    for (const c of decimalCommaCols) {
      const v = rows[r][c];
      if (v && v.indexOf(",") !== -1) {
        const fixed = v.replace(/,/g, ".");
        if (isNumericValue(fixed)) {
          rows[r][c] = fixed;
          count++;
        }
      }
    }
  }
  if (count === 0) return { text, commaFixed: false, count: 0 };
  const q = (cell) => {
    if (
      cell.indexOf(sep) !== -1 ||
      cell.indexOf('"') !== -1 ||
      cell.indexOf("\n") !== -1 ||
      cell.indexOf("\r") !== -1
    ) {
      return '"' + cell.replace(/"/g, '""') + '"';
    }
    return cell;
  };
  const rebuilt = rows.map((r) => r.map(q).join(sep)).join("\n");
  return { text: rebuilt, commaFixed: true, count };
}

// ── Parsing helpers ───────────────────────────────────────────────────────────

function detectHeader(rows) {
  if (rows.length < 2) return true;
  const a = rows[0].filter((v) => !isNumericValue(v) && v.trim() !== "").length;
  const b = rows[1].filter((v) => !isNumericValue(v) && v.trim() !== "").length;
  if (a > b) return true;
  if (a === b && a > 0) {
    let reps = 0;
    for (let i = 1; i < Math.min(rows.length, 20); i++)
      for (let c = 0; c < rows[0].length; c++)
        if (rows[i][c] && rows[i][c].trim() === rows[0][c].trim()) reps++;
    return reps < rows[0].length;
  }
  return a > 0;
}

function parseRaw(text, sepOv = "") {
  const sep = autoDetectSep(text, sepOv);
  const all = tokenizeDelimited(text, sep);
  if (all.length < 1) return { headers: [], rows: [], hasHeader: false, injectionWarnings: null };
  const mx = Math.max(...all.map((r) => r.length));
  const pad = all.map((r) => {
    while (r.length < mx) r.push("");
    return r;
  });
  const hh = detectHeader(pad);
  let headers, rows;
  if (hh) {
    headers = pad[0];
    rows = pad.slice(1);
  } else {
    headers = pad[0].map((_, i) => `Col_${i + 1}`);
    rows = pad;
  }
  const scan = scanForFormulaInjection(headers, rows);
  return {
    headers,
    rows,
    hasHeader: !!hh,
    injectionWarnings: scan.count > 0 ? scan : null,
  };
}

function guessColumnType(vals) {
  const ne = vals.filter((v) => v != null && v !== "");
  if (ne.length === 0) return "ignore";
  if (ne.filter((v) => isNumericValue(v)).length / ne.length > 0.8) {
    // Years (2024 / 2025 / 2026), binary flags (0 / 1), and small integer
    // enumerations are 100 % numeric but semantically categorical. Demote to
    // "group" before the value branch returns: small distinct count, all
    // integer, and many repetitions per value (cardinality << row count).
    // Threshold matches the "group" rule below (≤ 12 distinct, < 30 % of
    // rows) — tighter than the generic ≤ 20 to avoid pulling continuous
    // small-N data (e.g. 5 unique fluorescence intensities) into the wrong
    // bucket.
    const u = new Set(ne);
    if (u.size <= 12 && u.size < ne.length * 0.3) {
      const allIntegers = ne.every((v) => {
        const n = Number(String(v).trim());
        return Number.isFinite(n) && Number.isInteger(n);
      });
      if (allIntegers) return "group";
    }
    return "value";
  }
  const u = new Set(ne);
  if (u.size <= 20 && u.size < ne.length * 0.5) return "group";
  return "filter";
}

function detectWideFormat(headers, rows) {
  if (headers.length < 2 || rows.length < 2) return false;
  const numericCols = headers.map((_, ci) => {
    const vals = rows.map((r) => r[ci]).filter((v) => v !== "");
    return vals.length > 0 && vals.filter((v) => isNumericValue(v)).length / vals.length > 0.8;
  });
  return numericCols.every(Boolean);
}

// Wide-matrix parser for heatmap-style data:
//   first row     = column labels (the leading cell is the row-label-column
//                   heading and may be blank or any token — we drop it)
//   first column  = row labels
//   everything else = numeric values (non-numeric cells become NaN and are
//                   counted in warnings.nonNumeric so the UI can surface them)
// Returns { rowLabels, colLabels, matrix, warnings } where matrix is a
// 2-D array shaped [rowLabels.length][colLabels.length].
function parseWideMatrix(text, sepOv = "") {
  const parsed = parseRaw(text, sepOv);
  const { headers, rows, injectionWarnings } = parsed;
  if (headers.length < 2 || rows.length < 1) {
    return {
      rowLabels: [],
      colLabels: [],
      matrix: [],
      warnings: { nonNumeric: 0, emptyRows: 0, emptyCols: 0 },
      injectionWarnings: null,
    };
  }
  const colLabels = headers.slice(1);
  const rowLabels = [];
  const matrix = [];
  let nonNumeric = 0;
  rows.forEach((r) => {
    const label = r[0] == null ? "" : String(r[0]);
    const values = new Array(colLabels.length);
    for (let ci = 0; ci < colLabels.length; ci++) {
      const raw = r[ci + 1];
      if (raw == null || raw === "") {
        values[ci] = NaN;
      } else if (isNumericValue(raw)) {
        values[ci] = toNumericValue(raw);
      } else {
        values[ci] = NaN;
        nonNumeric++;
      }
    }
    rowLabels.push(label);
    matrix.push(values);
  });
  return { rowLabels, colLabels, matrix, warnings: { nonNumeric }, injectionWarnings };
}

// ── Unified data parsing ─────────────────────────────────────────────────────

function parseData(text, sepOv = "") {
  const sep = autoDetectSep(text, sepOv);
  const all = tokenizeDelimited(text, sep);
  if (all.length < 2) return { headers: [], data: [], rawData: [], injectionWarnings: null };
  const headers = all[0];
  const nCols = headers.length;
  const data = [],
    rawData = [];
  for (let i = 1; i < all.length; i++) {
    const rawVals = all[i].slice();
    while (rawVals.length < nCols) rawVals.push("");
    if (rawVals.every((v) => v === "")) continue;
    data.push(rawVals.map((s) => (isNumericValue(s) ? toNumericValue(s) : null)));
    rawData.push(rawVals);
  }
  const scan = scanForFormulaInjection(headers, rawData);
  return { headers, data, rawData, injectionWarnings: scan.count > 0 ? scan : null };
}

function dataToColumns(data, nCols) {
  const columns = Array.from({ length: nCols }, () => []);
  for (const row of data) {
    for (let c = 0; c < nCols; c++) {
      if (row[c] != null) columns[c].push(row[c]);
    }
  }
  return columns;
}

// ── Wide / long format helpers ────────────────────────────────────────────────

// Returns `{ headers, rows, skipped }`. `skipped` is the number of (row,
// column) cells that were empty or non-numeric and therefore omitted from
// the long output — surfaced by the upload-step UX so the user knows when
// the reshape silently shrank the dataset.
function wideToLong(headers, rows) {
  const longRows = [];
  let skipped = 0;
  rows.forEach((r) => {
    headers.forEach((h, ci) => {
      if (r[ci] !== "" && isNumericValue(r[ci])) {
        longRows.push([h, r[ci]]);
      } else {
        skipped++;
      }
    });
  });
  return { headers: ["Group", "Value"], rows: longRows, skipped };
}

// Returns `{ headers, rows, unlabelled }`. `unlabelled` is the number of
// input rows whose group cell was empty and therefore collapsed into the
// "?" bucket — surfaced by the download tile so the user knows multiple
// rows merged under a single placeholder name.
function reshapeWide(rows, gi, vi) {
  const g = {};
  let unlabelled = 0;
  rows.forEach((r) => {
    const raw = r[gi];
    if (raw === "" || raw == null) unlabelled++;
    const k = raw || "?";
    if (!g[k]) g[k] = [];
    g[k].push(r[vi]);
  });
  const vals = Object.values(g);
  if (vals.length === 0) return { headers: [], rows: [], unlabelled };
  const mx = Math.max(...vals.map((v) => v.length));
  const names = Object.keys(g);
  const w = [];
  for (let i = 0; i < mx; i++) w.push(names.map((n) => (g[n][i] != null ? g[n][i] : "")));
  return { headers: names, rows: w, unlabelled };
}

// ── Set-membership parsing (Venn / UpSet) ─────────────────────────────────────

// Wide format: each column is one set, cells are item ids. Preserves the
// column order via Map so downstream colour/index assignment is deterministic.
function parseSetData(headers, rows) {
  const sets = new Map();
  for (let ci = 0; ci < headers.length; ci++) {
    const s = new Set();
    for (const r of rows) {
      const v = (r[ci] || "").trim();
      if (v) s.add(v);
    }
    if (s.size > 0) sets.set(headers[ci], s);
  }
  const setNames = [...sets.keys()];
  return { setNames, sets };
}

// Long format: exactly two columns — item id, set name. Pivots into the same
// {setNames, sets} shape as parseSetData. setNames are ordered by first
// appearance in the input. Throws if the table doesn't have exactly 2 columns.
function parseLongFormatSets(headers, rows) {
  if (!headers || headers.length !== 2) {
    throw new Error("Long format requires exactly 2 columns (item, set).");
  }
  const sets = new Map();
  for (const r of rows) {
    const item = (r[0] || "").trim();
    const setName = (r[1] || "").trim();
    if (!item || !setName) continue;
    if (!sets.has(setName)) sets.set(setName, new Set());
    sets.get(setName).add(item);
  }
  const setNames = [...sets.keys()];
  return { setNames, sets };
}

// ── Statistics ────────────────────────────────────────────────────────────────

function computeStats(arr) {
  const n = arr.length;
  if (n === 0) return null;
  const mean = arr.reduce((a, b) => a + b, 0) / n;
  const variance = arr.reduce((s, v) => s + (v - mean) ** 2, 0) / (n > 1 ? n - 1 : 1);
  const sd = Math.sqrt(variance);
  const sem = n > 1 ? sd / Math.sqrt(n) : 0;
  // 95% CI half-width (two-sided t-critical × SEM). Matches lineplot's per-x
  // CI at line 86. Falls back to 0 when n<2 or tinv is unavailable (shared.js
  // loads before stats.js, but this runs at call time when tinv is global).
  const ci95 = n > 1 && typeof tinv === "function" ? tinv(0.975, n - 1) * sem : 0;
  const sorted = [...arr].sort((a, b) => a - b);
  const min = sorted[0];
  const max = sorted[n - 1];
  const median = n % 2 === 0 ? (sorted[n / 2 - 1] + sorted[n / 2]) / 2 : sorted[Math.floor(n / 2)];
  return { mean, sd, sem, ci95, n, min, max, median };
}

function quartiles(arr) {
  const s = [...arr].sort((a, b) => a - b),
    n = s.length;
  if (n === 0) return null;
  const q = (p) => {
    const i = p * (n - 1),
      lo = Math.floor(i),
      hi = Math.min(Math.ceil(i), n - 1);
    return lo === hi ? s[lo] : s[lo] * (hi - i) + s[hi] * (i - lo);
  };
  const q1 = q(0.25),
    med = q(0.5),
    q3 = q(0.75),
    iqr = q3 - q1;
  return {
    min: s[0],
    max: s[n - 1],
    q1,
    med,
    q3,
    iqr,
    wLo: Math.min(s.find((v) => v >= q1 - 1.5 * iqr) ?? s[0], q1),
    wHi: Math.max([...s].reverse().find((v) => v <= q3 + 1.5 * iqr) ?? s[n - 1], q3),
    n,
  };
}

function kde(values, nPoints = 50) {
  const n = values.length;
  if (n === 0) return [];
  const sorted = [...values].sort((a, b) => a - b);
  const min = sorted[0],
    max = sorted[n - 1];
  const iqr = n >= 4 ? sorted[Math.floor(n * 0.75)] - sorted[Math.floor(n * 0.25)] : max - min;
  const mean = values.reduce((a, b) => a + b, 0) / n;
  const variance = values.reduce((s, v) => s + (v - mean) ** 2, 0) / n;
  const std = Math.sqrt(variance);
  const bw = 1.06 * Math.min(std, (iqr || 1) / 1.34) * n ** -0.2 || 1;
  const pad = bw * 2;
  const lo = min - pad,
    hi = max + pad;
  const step = (hi - lo) / (nPoints - 1);
  const pts = [];
  for (let i = 0; i < nPoints; i++) {
    const x = lo + i * step;
    let density = 0;
    for (let j = 0; j < n; j++) {
      const z = (x - values[j]) / bw;
      density += Math.exp(-0.5 * z * z);
    }
    density /= n * bw * Math.sqrt(2 * Math.PI);
    pts.push({ x, d: density });
  }
  return pts;
}

function computeGroupStats(groups) {
  return Object.entries(groups).map(([name, vals]) => {
    const nums = vals.filter((v) => v !== "" && isNumericValue(v)).map(toNumericValue);
    const stats = computeStats(nums);
    if (!stats)
      return { name, n: 0, mean: null, sd: null, sem: null, min: null, max: null, median: null };
    return { name, ...stats };
  });
}

// ── Download helpers ──────────────────────────────────────────────────────────

// Sanitize an arbitrary string into an SVG-safe id fragment so exported
// <g id="..."> values are valid NCNames and show up as readable group names
// in Inkscape's Objects panel / XML editor. Non-alphanumerics become hyphens,
// runs are collapsed, edges trimmed, and a leading digit is prefixed with "_".
function svgSafeId(s) {
  if (s == null) return "unnamed";
  const cleaned = String(s)
    .replace(/[^A-Za-z0-9_.-]+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "");
  if (!cleaned) return "unnamed";
  return /^[A-Za-z_]/.test(cleaned) ? cleaned : "_" + cleaned;
}

function fileBaseName(fileName, fallback) {
  if (typeof fileName === "string" && fileName.trim()) return fileName.replace(/\.[^.]+$/, "");
  return fallback || "data";
}

function flashSaved(btn) {
  if (!btn) return;
  const original = btn.innerHTML;
  btn.innerHTML = "✓ Saved";
  btn.disabled = true;
  setTimeout(() => {
    btn.innerHTML = original;
    btn.disabled = false;
  }, 1500);
}

// Height of the reserved bottom band added to every export so the
// `Plöttr v…` attribution sits outside the plot area. Used by both
// `appendPlottrAttribution` (which extends the viewBox) and
// `downloadPng` (which sizes its raster canvas to the post-watermark
// dimensions, since the live SVG element still has the pre-watermark
// viewBox).
const PLOTTR_ATTRIBUTION_PAD = 14;

// Build a clone of `svgEl` ready for export and append the permanent
// `Plöttr v<VERSION>` attribution band at the bottom. Returns the
// cloned <svg> element — callers can serialize it to a string or read
// its updated `viewBox` / `width` / `height` attributes.
//
// Two pre-watermark transformations, both Inkscape workarounds:
//
//   1. Strip the root <svg> inline `style="max-width:100%;height:auto;..."`
//      (responsive-layout sugar that only makes sense inside an HTML flow;
//      Inkscape's CSS engine can collapse the computed viewport when it sees
//      `height: auto` on a root <svg>).
//
//   2. Strip every `shape-rendering="crispEdges"` attribute. This matters for
//      the heatmap, where the cells group carries crispEdges to keep browser
//      PNG rasterisation seamless. Inkscape ≥1.1 has a cairo-renderer bug
//      where crispEdges on a group containing thousands of small rects (esp.
//      sub-pixel-height ones like heatmap cells at 2 px tall) collapses the
//      whole group to default-fill (black). Our cell rects are already on
//      integer pixel coordinates via Math.round in the layout code, so
//      crispEdges is redundant for seam avoidance in the exported file — we
//      just drop it on export.
//
// The watermark itself extends the viewBox (and `height` attribute, if
// present) downward by PLOTTR_ATTRIBUTION_PAD px so the plot area, axes
// and existing margins stay pixel-identical — only the canvas grows.
function buildExportSvg(svgEl) {
  const clone = svgEl.cloneNode(true);
  clone.removeAttribute("style");
  clone.querySelectorAll("[shape-rendering]").forEach((el) => {
    el.removeAttribute("shape-rendering");
  });
  appendPlottrAttribution(clone);
  return clone;
}

function serializeSvgForExport(svgEl) {
  return new XMLSerializer().serializeToString(buildExportSvg(svgEl));
}

// Append the `<g id="plottr-attribution">` wrapper containing a small
// italic `Plöttr v<VERSION>` text to the bottom-right of the SVG
// canvas. Mutates the passed-in element — pass a clone, not the live
// DOM node. Idempotent: a second call removes the prior attribution
// before re-appending, so the canvas can't grow twice.
function appendPlottrAttribution(svgEl) {
  if (!svgEl || typeof svgEl.setAttribute !== "function") return;
  // Idempotency — if a prior attribution exists, strip both the group
  // and the canvas pad it added before recomputing so repeated calls
  // don't stack the band.
  const prior = svgEl.querySelector("#plottr-attribution");
  const hadPrior = !!(prior && prior.parentNode === svgEl);
  if (hadPrior) prior.parentNode.removeChild(prior);

  const vbParts = (svgEl.getAttribute("viewBox") || "").split(/[\s,]+/).map(parseFloat);
  let vbX = 0;
  let vbY = 0;
  let vbW = 0;
  let vbH = 0;
  if (vbParts.length >= 4 && vbParts.every((n) => Number.isFinite(n))) {
    vbX = vbParts[0];
    vbY = vbParts[1];
    vbW = vbParts[2];
    vbH = vbParts[3];
  } else {
    const wAttr = parseFloat(svgEl.getAttribute("width"));
    const hAttr = parseFloat(svgEl.getAttribute("height"));
    vbW = Number.isFinite(wAttr) ? wAttr : 0;
    vbH = Number.isFinite(hAttr) ? hAttr : 0;
  }
  if (hadPrior) vbH -= PLOTTR_ATTRIBUTION_PAD;
  if (!(vbW > 0) || !(vbH > 0)) return;

  const newH = vbH + PLOTTR_ATTRIBUTION_PAD;
  svgEl.setAttribute("viewBox", `${vbX} ${vbY} ${vbW} ${newH}`);
  const heightAttr = parseFloat(svgEl.getAttribute("height"));
  if (Number.isFinite(heightAttr)) {
    const baseHeight = hadPrior ? heightAttr - PLOTTR_ATTRIBUTION_PAD : heightAttr;
    svgEl.setAttribute("height", String(baseHeight + PLOTTR_ATTRIBUTION_PAD));
  }

  const version =
    (typeof window !== "undefined" && typeof window.__APP_VERSION__ === "string"
      ? window.__APP_VERSION__
      : null) || "v?";
  const doc = svgEl.ownerDocument || (typeof document !== "undefined" ? document : null);
  if (!doc || typeof doc.createElementNS !== "function") return;
  const NS = "http://www.w3.org/2000/svg";
  const g = doc.createElementNS(NS, "g");
  g.setAttribute("id", "plottr-attribution");
  g.setAttribute("data-plottr-version", version);
  const text = doc.createElementNS(NS, "text");
  text.setAttribute("x", String(vbX + vbW - 5));
  text.setAttribute("y", String(vbY + newH - 4));
  text.setAttribute("font-size", "8");
  text.setAttribute("font-style", "italic");
  text.setAttribute("fill", "#999");
  text.setAttribute("text-anchor", "end");
  text.setAttribute("font-family", "system-ui, -apple-system, sans-serif");
  text.textContent = `Plöttr ${version}`;
  g.appendChild(text);
  svgEl.appendChild(g);
}

// MIME + accept-extension lookup keyed by filename extension. Drives
// the native save-picker's `types` filter so users see the right
// extension highlighted in the dialog.
const _SAVE_PICKER_TYPES = {
  ".svg": { mime: "image/svg+xml", description: "SVG image" },
  ".png": { mime: "image/png", description: "PNG image" },
  ".csv": { mime: "text/csv", description: "CSV file" },
  ".tsv": { mime: "text/tab-separated-values", description: "TSV file" },
  ".txt": { mime: "text/plain", description: "Text file" },
  ".r": { mime: "text/plain", description: "R script" },
  ".json": { mime: "application/json", description: "JSON file" },
};

// Save a Blob to disk. Tries the File System Access API
// (`window.showSaveFilePicker`) first so the user can pick a target
// folder + filename — supported in Chromium-based browsers (Chrome,
// Edge, Opera) on HTTPS / localhost. Falls back to the classic
// `<a download>` anchor click on Firefox / Safari, which routes the
// file to the browser's default Downloads folder.
//
// The fallback is also taken when the picker call throws anything
// other than the user-cancelled `AbortError` — for instance if the
// page is loaded inside a sandboxed iframe that strips the API. User
// cancel returns silently; we don't downgrade to the fallback in that
// case because the user explicitly chose "Cancel".
async function saveBlob(blob, filename) {
  if (typeof window !== "undefined" && typeof window.showSaveFilePicker === "function") {
    try {
      const dot = filename.lastIndexOf(".");
      const ext = dot >= 0 ? filename.slice(dot).toLowerCase() : "";
      const meta = _SAVE_PICKER_TYPES[ext] || {
        mime: blob.type || "application/octet-stream",
        description: "File",
      };
      const handle = await window.showSaveFilePicker({
        suggestedName: filename,
        types: [{ description: meta.description, accept: { [meta.mime]: [ext || ""] } }],
      });
      const writable = await handle.createWritable();
      await writable.write(blob);
      await writable.close();
      return;
    } catch (err) {
      // User cancelled — respect it, do nothing.
      if (err && err.name === "AbortError") return;
      // Picker threw for some other reason (sandboxed iframe, http://
      // local file load, missing OS handler). Fall through to the
      // legacy anchor fallback so the user still gets the file.
    }
  }
  // Legacy fallback — drops the file in the browser's default Downloads
  // folder via a hidden <a download> click.
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.style.display = "none";
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

function downloadSvg(svgEl, filename) {
  if (!svgEl) return;
  const svgStr = serializeSvgForExport(svgEl);
  const blob = new Blob([svgStr], { type: "image/svg+xml" });
  // Fire-and-forget — the helper's promise resolves once the user
  // picks a folder (or the fallback anchor click completes); callers
  // don't need to await.
  saveBlob(blob, filename);
}
function downloadPng(svgEl, filename, scale) {
  if (!svgEl) return;
  scale = scale || 2;
  // Build the export clone once so the raster canvas matches the
  // watermarked viewBox — the live element still has the pre-attribution
  // dimensions, but the SVG we rasterise has the extra bottom band.
  const exportSvg = buildExportSvg(svgEl);
  const svgStr = new XMLSerializer().serializeToString(exportSvg);
  const vb = exportSvg.getAttribute("viewBox");
  const parts = vb ? vb.split(/[\s,]+/) : [];
  const w = parts.length >= 4 ? parseFloat(parts[2]) : svgEl.clientWidth || 800;
  const h =
    parts.length >= 4 ? parseFloat(parts[3]) : (svgEl.clientHeight || 600) + PLOTTR_ATTRIBUTION_PAD;
  const canvas = document.createElement("canvas");
  canvas.width = w * scale;
  canvas.height = h * scale;
  const ctx = canvas.getContext("2d");
  ctx.fillStyle = "#ffffff";
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  const img = new Image();
  const blob = new Blob([svgStr], { type: "image/svg+xml;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  img.onload = function () {
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    URL.revokeObjectURL(url);
    canvas.toBlob(function (pngBlob) {
      // The user-gesture window for `showSaveFilePicker` is normally
      // tight, but Chromium grants extra slack to async chains rooted
      // in a click handler — the canvas → blob round-trip stays
      // within that allowance for typical chart sizes.
      saveBlob(pngBlob, filename);
    }, "image/png");
  };
  img.src = url;
}
function downloadText(text, filename) {
  const blob = new Blob([text], { type: "text/plain" });
  saveBlob(blob, filename);
}

// Cells whose first character is one of these get a leading single-quote
// before the CSV escape. Excel / LibreOffice / Google Sheets all treat `=`,
// `+`, `-`, `@` (and a leading tab / CR before any of those) as a formula
// trigger; the prepended `'` tells the spreadsheet engine to treat the cell
// as text. This is the standard OWASP CSV-injection mitigation. Plöttr never
// evaluates the formula itself, so the laundering happens in the *consumer*
// of the exported file — see docs/security_audit_02-05-2026.md item #1.
//
// `_isFormulaInjection` adds the obvious carve-out the raw OWASP rule
// misses for scientific data: a cell that *parses cleanly as a number*
// (per `isNumericValue`) is just a negative or signed value like `-0.5`
// or `-1.5e3` — Excel reads that as a number, not a formula, so we leave
// it alone (no banner noise, no apostrophe drift on round-trip). Hostile
// strings like `-cmd|'/c calc'!A0`, `-2-3+10`, `+evil`, `=5`, `@SUM(...)`,
// or a leading TAB / CR are all rejected by `isNumericValue` and so still
// get the prefix.
const _CSV_FORMULA_LEAD = /^[=+\-@\t\r]/;

function _isFormulaInjection(s) {
  return _CSV_FORMULA_LEAD.test(s) && !isNumericValue(s);
}

function _escapeCsvCell(v) {
  let s = String(v);
  if (_isFormulaInjection(s)) s = "'" + s;
  return `"${s.replace(/"/g, '""')}"`;
}

// RFC 4180 CSV string builder. Pure (no DOM / Blob) so it round-trips through
// `parseRaw` in tests without needing a browser context. Headers go through
// the same escape as data cells — a header containing a comma
// ("Sample, Note") used to write a malformed first line that Plöttr's own
// parseRaw split into N+1 columns on re-import. Cells starting with a
// formula-trigger character are prefixed with `'` (see _escapeCsvCell).
function buildCsvString(headers, rows) {
  return [
    headers.map(_escapeCsvCell).join(","),
    ...rows.map((r) => r.map(_escapeCsvCell).join(",")),
  ].join("\n");
}

// Scan parsed headers + rows for cells that would trigger formula evaluation
// when re-opened in Excel / LibreOffice / Sheets — same character set as
// _CSV_FORMULA_LEAD. Used at ingest time to surface a warning banner so the
// user knows their pasted dataset is laundering hostile content even if
// they never download it. Returns { count, headers: [{idx, value}], cells:
// [{row, col, header, value}] } where the example arrays are capped (cap
// defaults to 8 for each) so the banner stays compact on huge sheets.
function scanForFormulaInjection(headers, rows, opts) {
  const cap = (opts && opts.cap) || 8;
  const out = { count: 0, headers: [], cells: [] };
  if (Array.isArray(headers)) {
    for (let i = 0; i < headers.length; i++) {
      const v = headers[i];
      if (typeof v !== "string" || !_isFormulaInjection(v)) continue;
      out.count++;
      if (out.headers.length < cap) out.headers.push({ idx: i, value: v });
    }
  }
  if (Array.isArray(rows)) {
    for (let r = 0; r < rows.length; r++) {
      const row = rows[r];
      if (!Array.isArray(row)) continue;
      for (let c = 0; c < row.length; c++) {
        const v = row[c];
        if (typeof v !== "string" || !_isFormulaInjection(v)) continue;
        out.count++;
        if (out.cells.length < cap) {
          out.cells.push({
            row: r,
            col: c,
            header: headers && headers[c] != null ? String(headers[c]) : null,
            value: v,
          });
        }
      }
    }
  }
  return out;
}

function downloadCsv(headers, rows, filename) {
  const blob = new Blob([buildCsvString(headers, rows)], { type: "text/csv" });
  saveBlob(blob, filename);
}

// ──────────────────────────────────────────────────────────────────
// stats-dist.js
// ──────────────────────────────────────────────────────────────────
// stats-dist.js — probability distributions, special functions, and power calcs.
//
// Loaded as a plain <script> tag through tools/shared.bundle.js (concatenated
// in scripts/build-shared.js order). Top-level declarations stay as browser
// globals; tools and tests consume these names without imports.
//
// Layout:
//   1.  Distribution functions  — normal, gamma, beta, t, F, chi-square,
//                                 noncentral t/F/chi-square
//   2.  Generic helpers         — bisect
//   2b. Power functions         — t / paired / ANOVA / correlation / chi²
//
// All functions are benchmarked against R output in tests/stats.test.js
// with a ±0.5 % tolerance bar.

// ── 1. Distribution functions ───────────────────────────────────────────────

// Normal CDF. Uses A&S 26.2.17 (max error 7.5e-8) for moderate |x|, and
// switches to the tail-accurate `normsf` for |x| ≥ 7 — avoids the 1 − tiny
// representation collapse at the edges of double precision.
function normcdf(x) {
  if (x === 0) return 0.5;
  if (x >= 7) return 1 - normsf(x);
  if (x <= -7) return normsf(-x);
  const t = 1 / (1 + 0.2316419 * Math.abs(x));
  const d = 0.3989422804014327; // 1/sqrt(2*pi)
  const poly =
    t *
    (0.31938153 + t * (-0.356563782 + t * (1.781477937 + t * (-1.821255978 + t * 1.330274429))));
  const p = 1 - d * Math.exp(-0.5 * x * x) * poly;
  return x > 0 ? p : 1 - p;
}

// Normal survival 1 - Φ(x) — tail-accurate. For |x| < 7 we use the A&S 26.2.17
// polynomial directly (no 1 − normcdf cancellation). For |x| ≥ 7 we switch to
// the asymptotic expansion Φ̄(x) ≈ φ(x)/x · (1 − 1/x² + 3/x⁴ − 15/x⁶ + ...)
// which stays accurate down to ~1e-300 where A&S 26.2.17 has already lost all
// meaningful digits.
function normsf(x) {
  if (x === 0) return 0.5;
  if (x < 0) return 1 - normsf(-x);
  const d = 0.3989422804014327; // 1/sqrt(2*pi)
  if (x < 7) {
    const t = 1 / (1 + 0.2316419 * x);
    const poly =
      t *
      (0.31938153 + t * (-0.356563782 + t * (1.781477937 + t * (-1.821255978 + t * 1.330274429))));
    return d * Math.exp(-0.5 * x * x) * poly;
  }
  // Asymptotic series. Truncate when a term is ≤ 1e-16 × running sum.
  const x2 = x * x;
  let term = 1;
  let sum = 1;
  let n = 1;
  while (n < 40) {
    term *= -(2 * n - 1) / x2;
    const next = sum + term;
    if (Math.abs(term) <= 1e-16 * Math.abs(next)) {
      sum = next;
      break;
    }
    sum = next;
    n++;
  }
  return (d * Math.exp(-0.5 * x2) * sum) / x;
}

// Inverse normal CDF — Peter Acklam's rational approximation (max error 1.15e-9)
function norminv(p) {
  if (p <= 0) return -Infinity;
  if (p >= 1) return Infinity;
  if (p === 0.5) return 0;
  const a = [
    -3.969683028665376e1, 2.209460984245205e2, -2.759285104469687e2, 1.38357751867269e2,
    -3.066479806614716e1, 2.506628277459239,
  ];
  const b = [
    -5.447609879822406e1, 1.615858368580409e2, -1.556989798598866e2, 6.680131188771972e1,
    -1.328068155288572e1,
  ];
  const c = [
    -7.784894002430293e-3, -3.223964580411365e-1, -2.400758277161838, -2.549732539343734,
    4.374664141464968, 2.938163982698783,
  ];
  const d = [7.784695709041462e-3, 3.224671290700398e-1, 2.445134137142996, 3.754408661907416];
  const pLow = 0.02425,
    pHigh = 1 - pLow;
  let q, r;
  if (p < pLow) {
    q = Math.sqrt(-2 * Math.log(p));
    return (
      (((((c[0] * q + c[1]) * q + c[2]) * q + c[3]) * q + c[4]) * q + c[5]) /
      ((((d[0] * q + d[1]) * q + d[2]) * q + d[3]) * q + 1)
    );
  }
  if (p <= pHigh) {
    q = p - 0.5;
    r = q * q;
    return (
      ((((((a[0] * r + a[1]) * r + a[2]) * r + a[3]) * r + a[4]) * r + a[5]) * q) /
      (((((b[0] * r + b[1]) * r + b[2]) * r + b[3]) * r + b[4]) * r + 1)
    );
  }
  q = Math.sqrt(-2 * Math.log(1 - p));
  return (
    -(((((c[0] * q + c[1]) * q + c[2]) * q + c[3]) * q + c[4]) * q + c[5]) /
    ((((d[0] * q + d[1]) * q + d[2]) * q + d[3]) * q + 1)
  );
}

// Log gamma — Lanczos approximation
function gammaln(x) {
  const g = 7;
  const coef = [
    0.99999999999980993, 676.5203681218851, -1259.1392167224028, 771.32342877765313,
    -176.61502916214059, 12.507343278686905, -0.13857109526572012, 9.9843695780195716e-6,
    1.5056327351493116e-7,
  ];
  if (x < 0.5) return Math.log(Math.PI / Math.sin(Math.PI * x)) - gammaln(1 - x);
  x -= 1;
  let a = coef[0];
  const t = x + g + 0.5;
  for (let i = 1; i < g + 2; i++) a += coef[i] / (x + i);
  return 0.5 * Math.log(2 * Math.PI) + (x + 0.5) * Math.log(t) - t + Math.log(a);
}

// Regularized incomplete beta function I_x(a, b) via continued fraction.
//
// Log-space final exponentiation: the prior `exp(logFront) * cf / a` path
// underflowed `logFront` to 0 whenever `a*log(x) + b*log(1-x) - lnBeta` went
// below ≈ −745 (double-precision exp floor). That silently destroyed deep-tail
// p-values — the small-t branch for df/2 ≥ 30 with |t| > 5 routinely lands
// at logFront ≈ −200 to −140, well within representable range but wiped to 0
// if we exp() too early.
function betai(a, b, x) {
  if (x < 0 || x > 1) return 0;
  if (x === 0) return 0;
  if (x === 1) return 1;
  const lnBeta = gammaln(a) + gammaln(b) - gammaln(a + b);
  const logFront = Math.log(x) * a + Math.log(1 - x) * b - lnBeta;
  if (x < (a + 1) / (a + b + 2)) {
    const cf = betacf(a, b, x);
    return Math.exp(logFront + Math.log(cf / a));
  }
  const cf = betacf(b, a, 1 - x);
  return 1 - Math.exp(logFront + Math.log(cf / b));
}

// Upper-tail of the regularized incomplete beta: 1 − I_x(a, b). Computing
// 1 − betai() directly cancels when betai is near 1; this helper returns the
// upper tail via the opposite branch of the continued fraction, so callers
// like `fcdf_upper` and `tcdf_upper` stay accurate for tiny p-values.
function betai_upper(a, b, x) {
  if (x <= 0) return 1;
  if (x >= 1) return 0;
  const lnBeta = gammaln(a) + gammaln(b) - gammaln(a + b);
  const logFront = Math.log(x) * a + Math.log(1 - x) * b - lnBeta;
  if (x < (a + 1) / (a + b + 2)) {
    // betai is small → 1 − tiny; direct subtraction is fine.
    const cf = betacf(a, b, x);
    return 1 - Math.exp(logFront + Math.log(cf / a));
  }
  // betai is ≈ 1 → upper tail = exp(logFront + log(cf/b)), no cancellation.
  const cf = betacf(b, a, 1 - x);
  return Math.exp(logFront + Math.log(cf / b));
}

// ── Continued-fraction primitives — Cephes-derived ──────────────────────────
//
// betacf, gammainc, and gammainc_upper below are ported from the Cephes
// Mathematical Library (Stephen L. Moshier), which the author dedicated to
// the public domain. See `incbet.c` and `igam.c` at:
//   https://www.netlib.org/cephes/
//   "Cephes Math Library Release 2.8" — Stephen L. Moshier, 2000
//
// Cephes uses a three-term recurrence (pkm1/pkm2/qkm1/qkm2) with periodic
// big/biginv rescaling to keep partial numerators/denominators inside
// representable range. This is structurally distinct from Lentz's modified
// per-step floor clamp; both converge to the same value within machine
// precision for the input range we use here. The Plöttr-specific polish
// (log-space final exponentiation in gammainc / gammainc_upper, and the
// √a-scaled iteration cap so chi2cdf / ptukey stay accurate at huge df)
// is layered on top of the Cephes recurrence.
//
// Constants below match Cephes' incbet.c / igam.c literally.
const CEPHES_BIG = 4.503599627370496e15; // 2^52
const CEPHES_BIGINV = 2.220446049250313e-16; // 2^-52
const CEPHES_MACHEP = 1.1102230246251565e-16;

// Continued fraction for the regularized incomplete beta — forward form
// (Cephes' incbcf). Returns the bare CF value `pk/qk`; betai / betai_upper
// then multiply by the log-space prefactor.
function betacf(a, b, x) {
  let k1 = a;
  let k2 = a + b;
  let k3 = a;
  let k4 = a + 1;
  let k5 = 1;
  let k6 = b - 1;
  let k7 = k4;
  let k8 = a + 2;

  let pkm2 = 0;
  let qkm2 = 1;
  let pkm1 = 1;
  let qkm1 = 1;
  let ans = 1;
  let r = 1;
  const thresh = 3 * CEPHES_MACHEP;

  for (let n = 0; n < 300; n++) {
    let xk = -((x * k1 * k2) / (k3 * k4));
    let pk = pkm1 + pkm2 * xk;
    let qk = qkm1 + qkm2 * xk;
    pkm2 = pkm1;
    pkm1 = pk;
    qkm2 = qkm1;
    qkm1 = qk;

    xk = (x * k5 * k6) / (k7 * k8);
    pk = pkm1 + pkm2 * xk;
    qk = qkm1 + qkm2 * xk;
    pkm2 = pkm1;
    pkm1 = pk;
    qkm2 = qkm1;
    qkm1 = qk;

    let t;
    if (qk !== 0) r = pk / qk;
    if (r !== 0) {
      t = Math.abs((ans - r) / r);
      ans = r;
    } else {
      t = 1;
    }
    if (t < thresh) return ans;

    k1 += 1;
    k2 += 1;
    k3 += 2;
    k4 += 2;
    k5 += 1;
    k6 -= 1;
    k7 += 2;
    k8 += 2;

    if (Math.abs(qk) + Math.abs(pk) > CEPHES_BIG) {
      pkm2 *= CEPHES_BIGINV;
      pkm1 *= CEPHES_BIGINV;
      qkm2 *= CEPHES_BIGINV;
      qkm1 *= CEPHES_BIGINV;
    }
    if (Math.abs(qk) < CEPHES_BIGINV || Math.abs(pk) < CEPHES_BIGINV) {
      pkm2 *= CEPHES_BIG;
      pkm1 *= CEPHES_BIG;
      qkm2 *= CEPHES_BIG;
      qkm1 *= CEPHES_BIG;
    }
  }
  return ans;
}

// Regularized lower incomplete gamma P(a, x) — Cephes' igam series form.
// Cephes uses `r += 1; c *= x/r; ans += c` with a `c/ans < MACHEP`
// termination test. We layer a √a-scaled iteration cap on top because the
// series converges in ~O(√a) steps when x ≈ a (Poisson-like concentration
// around n ≈ x − a with width √a) — chi2cdf / ptukey at huge df otherwise
// truncate before convergence. Switchover threshold (`x > 1 && x > a`)
// matches Cephes literally, not NR's `x < a + 1`.
function gammainc(a, x) {
  if (x < 0) return 0;
  if (x === 0) return 0;
  if (x > 1 && x > a) return 1 - gammainc_upper(a, x);

  let r = a;
  let c = 1;
  let ans = 1;
  const maxIter = Math.max(700, Math.ceil(20 * Math.sqrt(a + 1)));
  for (let i = 0; i < maxIter; i++) {
    r += 1;
    c *= x / r;
    ans += c;
    if (c / ans < CEPHES_MACHEP) break;
  }
  // Log-space final exponentiation: the prefactor `exp(a*ln(x) - x - lnΓ(a))`
  // can underflow at large a even when ans*ax/a is well within range.
  return Math.exp(Math.log(ans / a) + a * Math.log(x) - x - gammaln(a));
}

// Regularized upper incomplete gamma Q(a, x) = 1 − P(a, x) — Cephes' igamc
// continued-fraction form. Three-term recurrence on (pkm, qkm) with the
// `pk = pkm1*z − pkm2*yc` update; `c` and `y` advance by integer steps each
// iteration. Big/biginv rescaling keeps |pk| from running away.
function gammainc_upper(a, x) {
  let y = 1 - a;
  let z = x + y + 1;
  let c = 0;
  let pkm2 = 1;
  let qkm2 = x;
  let pkm1 = x + 1;
  let qkm1 = z * x;
  let ans = pkm1 / qkm1;

  const maxIter = Math.max(300, Math.ceil(20 * Math.sqrt(a + 1)));
  for (let i = 0; i < maxIter; i++) {
    c += 1;
    y += 1;
    z += 2;
    const yc = y * c;
    const pk = pkm1 * z - pkm2 * yc;
    const qk = qkm1 * z - qkm2 * yc;
    let t;
    if (qk !== 0) {
      const r = pk / qk;
      t = Math.abs((ans - r) / r);
      ans = r;
    } else {
      t = 1;
    }
    pkm2 = pkm1;
    pkm1 = pk;
    qkm2 = qkm1;
    qkm1 = qk;
    if (Math.abs(pk) > CEPHES_BIG) {
      pkm2 *= CEPHES_BIGINV;
      pkm1 *= CEPHES_BIGINV;
      qkm2 *= CEPHES_BIGINV;
      qkm1 *= CEPHES_BIGINV;
    }
    if (t < CEPHES_MACHEP) break;
  }
  // Log-space final exponentiation — see comment in gammainc.
  return Math.exp(Math.log(ans) + a * Math.log(x) - x - gammaln(a));
}

// t-distribution CDF
function tcdf(t, df) {
  const x = df / (df + t * t);
  const p = 0.5 * betai(df / 2, 0.5, x);
  return t >= 0 ? 1 - p : p;
}

// Upper-tail 1 − tcdf(t, df). Avoids the `1 − (near-1)` cancellation that
// silently drove `tTest` p-values to 0 for |t| > ~9 at large df — e.g. iris
// SL setosa vs versicolor (t ≈ 10.5, df = 98) where R reports p ≈ 9e-18 but
// JS underflowed to 0 because tcdf returned a float-rounded 1.0.
function tcdf_upper(t, df) {
  const x = df / (df + t * t);
  const tail = 0.5 * betai(df / 2, 0.5, x);
  return t >= 0 ? tail : 1 - tail;
}

// t-distribution PDF (computed in log space, used by tinv Newton-Raphson)
function tpdf(x, df) {
  const logpdf =
    gammaln((df + 1) / 2) -
    gammaln(df / 2) -
    0.5 * Math.log(Math.PI * df) -
    ((df + 1) / 2) * Math.log(1 + (x * x) / df);
  return Math.exp(logpdf);
}

// Inverse t CDF.
// Strategy:
//   • df = 1 and df = 2 have closed forms — use them directly.
//   • df ≥ 3: Newton-Raphson seeded with a Cornish-Fisher correction to the
//     normal quantile, with a damped step and a bisection fallback if Newton
//     fails to converge. Bracket bounds expand outward (doubling) to handle
//     heavy-tailed cases where |t| can exceed hundreds or thousands at
//     extreme p (e.g. qt(1e-10, 5) ≈ −157).
//   • Work in the left tail (leftP ≤ 0.5) and flip sign at the end, so that
//     inputs like p = 1 − 1e-15 don't suffer catastrophic cancellation.
function tinv(p, df) {
  if (p <= 0) return -Infinity;
  if (p >= 1) return Infinity;
  if (p === 0.5) return 0;

  const upper = p > 0.5;
  const leftP = upper ? 1 - p : p;

  let tLeft;

  if (df === 1) {
    // Cauchy: F⁻¹(u) = tan(π(u − 0.5)) = −cot(π·u).
    tLeft = -1 / Math.tan(Math.PI * leftP);
  } else if (df === 2) {
    // Closed form: t = (2u−1) / √(2u(1−u)).
    tLeft = (2 * leftP - 1) / Math.sqrt(2 * leftP * (1 - leftP));
  } else {
    // Cornish-Fisher seed: first-order correction to the normal quantile.
    const z = norminv(leftP);
    let x = z + (z * (z * z + 1)) / (4 * df);

    let converged = false;
    for (let i = 0; i < 60; i++) {
      const cdf = tcdf(x, df);
      const pdf = tpdf(x, df);
      if (!Number.isFinite(cdf) || !(pdf > 0)) break;
      let step = (cdf - leftP) / pdf;
      // Damp the step so we can't jump past a flat tail where PDF → 0.
      const cap = Math.abs(x) + 1;
      if (step > cap) step = cap;
      else if (step < -cap) step = -cap;
      x -= step;
      if (Math.abs(step) < 1e-13 * (Math.abs(x) + 1)) {
        converged = true;
        break;
      }
    }

    if (converged && Number.isFinite(x)) {
      tLeft = x;
    } else {
      // Bisection fallback: expand the lower bound until leftP is bracketed.
      let lo = -1;
      const hi = 0;
      for (let i = 0; i < 4000 && tcdf(lo, df) > leftP; i++) lo *= 2;
      let a = lo,
        b = hi;
      for (let i = 0; i < 200; i++) {
        const mid = (a + b) / 2;
        if (tcdf(mid, df) < leftP) a = mid;
        else b = mid;
        if (b - a < 1e-12 * (Math.abs(a) + 1)) break;
      }
      tLeft = (a + b) / 2;
    }
  }

  return upper ? -tLeft : tLeft;
}

// F-distribution CDF
function fcdf(f, d1, d2) {
  if (f <= 0) return 0;
  return betai(d1 / 2, d2 / 2, (d1 * f) / (d1 * f + d2));
}

// Upper-tail 1 − fcdf(f, d1, d2). Same rationale as `tcdf_upper` — direct
// computation avoids the 1 − (near-1) cancellation that underflows ANOVA /
// Welch-ANOVA p-values at F > ~50.
function fcdf_upper(f, d1, d2) {
  if (f <= 0) return 1;
  return betai_upper(d1 / 2, d2 / 2, (d1 * f) / (d1 * f + d2));
}

// Chi-square CDF
function chi2cdf(x, k) {
  if (x <= 0) return 0;
  return gammainc(k / 2, x / 2);
}

// Chi-square PDF — used as the Newton derivative in chi2inv. Built in log
// space to avoid overflow at large k or tiny x.
function chi2pdf(x, k) {
  if (x <= 0) return 0;
  const halfK = k / 2;
  return Math.exp((halfK - 1) * Math.log(x) - x / 2 - halfK * Math.log(2) - gammaln(halfK));
}

// Inverse chi-square CDF — Newton-Raphson on the central body, bisection
// fallback for the saturated tails where the χ² CDF derivative collapses
// to ~10⁻¹² and Newton overshoots wildly. The historical implementation was
// pure bisection with a doubling upper bound (~50 iterations for 1e-10
// tolerance); this version is much faster on typical inputs while remaining
// correct on the tails. Uses the Wilson-Hilferty cubic-normal approximation
// (X/k)^(1/3) ≈ N(1 − 2/(9k), 2/(9k)) to seed both Newton and the bracket.
function chi2inv(p, k) {
  if (p <= 0) return 0;
  if (p >= 1) return Infinity;
  if (k <= 0) return NaN;
  const z = norminv(p);
  const h = 2 / (9 * k);
  let x = k * Math.pow(1 - h + z * Math.sqrt(h), 3);
  if (!(x > 0)) x = Math.max(1e-6, k * 0.01);
  // Newton inside a wide guard: only accept iterations that stay positive
  // and don't exceed twice the current point. If Newton makes <10⁻¹² PDF
  // (deep in the saturated tail) or the step would leave the guard, drop
  // straight to bisection.
  for (let i = 0; i < 30; i++) {
    const f = chi2cdf(x, k) - p;
    if (Math.abs(f) < 1e-12) return x;
    const fp = chi2pdf(x, k);
    if (!(fp > 1e-12)) break;
    const step = f / fp;
    const xNew = x - step;
    if (!(xNew > 0) || xNew > 2 * x || xNew < x / 2) break;
    if (Math.abs(xNew - x) < 1e-12 * Math.max(1, x)) return xNew;
    x = xNew;
  }
  // Bisection fallback. Use WH seed to set a tight initial bracket; expand
  // by doubling if it doesn't cover p (bisect itself refuses unbracketed
  // targets, so this guarantees progress).
  let lo = 0,
    hi = Math.max(x * 2, k + 10 * Math.sqrt(2 * k));
  for (let i = 0; i < 40 && chi2cdf(hi, k) < p; i++) hi *= 2;
  return bisect((q) => chi2cdf(q, k), p, lo, hi, 1e-10);
}

// Gauss-Legendre quadrature nodes and weights (computed once, cached)
let _glCache;
function _gaussLegendre(n) {
  if (_glCache && _glCache.n === n) return _glCache;
  const nodes = new Array(n),
    weights = new Array(n);
  for (let i = 0; i < Math.ceil(n / 2); i++) {
    let x = Math.cos((Math.PI * (i + 0.75)) / (n + 0.5));
    for (let it = 0; it < 100; it++) {
      let pm1 = 1,
        p = x;
      for (let j = 2; j <= n; j++) {
        const pp = ((2 * j - 1) * x * p - (j - 1) * pm1) / j;
        pm1 = p;
        p = pp;
      }
      const dp = (n * (x * p - pm1)) / (x * x - 1);
      const dx = p / dp;
      x -= dx;
      if (Math.abs(dx) < 1e-15) break;
    }
    let pm1 = 1,
      p = x;
    for (let j = 2; j <= n; j++) {
      const pp = ((2 * j - 1) * x * p - (j - 1) * pm1) / j;
      pm1 = p;
      p = pp;
    }
    const dp = (n * (x * p - pm1)) / (x * x - 1);
    const w = 2 / ((1 - x * x) * dp * dp);
    nodes[i] = -x;
    nodes[n - 1 - i] = x;
    weights[i] = w;
    weights[n - 1 - i] = w;
  }
  return (_glCache = { nodes, weights, n });
}

// Noncentral t CDF — Gauss-Legendre quadrature of chi-square mixture.
// P(T ≤ t | ν, δ) = ∫₀^∞ Φ(t√(s/ν) − δ) · f_χ²(s; ν) ds
// Substitution u = √s removes density singularity for small ν, giving:
// = ∫₀^∞ Φ(tu/√ν − δ) · 2u^{ν−1} e^{−u²/2} / (2^{ν/2} Γ(ν/2)) du
function nctcdf(t, df, delta) {
  if (Math.abs(delta) < 1e-14) return tcdf(t, df);
  const halfDf = df / 2;
  const logC = halfDf * Math.log(2) + gammaln(halfDf);
  const sqrtDf = Math.sqrt(df);
  const uLo = Math.max(0, sqrtDf - 8);
  const uHi = sqrtDf + 8;
  const gl = _gaussLegendre(48);
  const half = (uHi - uLo) / 2,
    mid = (uHi + uLo) / 2;
  let sum = 0;
  for (let i = 0; i < 48; i++) {
    const u = mid + half * gl.nodes[i];
    if (u <= 0) continue;
    const logH = Math.log(2) + (df - 1) * Math.log(u) - (u * u) / 2 - logC;
    sum += half * gl.weights[i] * normcdf((t * u) / sqrtDf - delta) * Math.exp(logH);
  }
  return Math.max(0, Math.min(1, sum));
}

// Noncentral F survival P(F' > f) — Poisson mixture
// F' = (χ²_{d1+2J}/d1) / (χ²_{d2}/d2), J~Poisson(λ/2)
// P(F'>f) = Σ_j P(J=j) × P(F(d1+2j, d2) > f × d1/(d1+2j))
// Starts at Poisson mode to avoid underflow for large λ.
function ncf_sf(f, d1, d2, lambda) {
  if (f <= 0) return 1;
  if (lambda <= 0) return fcdf_upper(f, d1, d2);
  const halfLam = lambda / 2;

  // Large-λ short circuit: the Poisson mass around the mode has width
  // σ = √(λ/2), so a fixed 500-step window leaves most of the mass
  // unaccounted for when λ is huge. In that regime, P(F'>f) is either
  // ≈ 1 or ≈ 0 for f outside a few σ of the NCF mean — use closed-form
  // mean / variance of the NCF (valid for d2 > 4) and short-circuit via
  // normal approximation when f is clearly in the far tail. Without this,
  // power-analysis sample-size solvers probe huge n values (e.g. via
  // bisect up to hi=100000) and get misleading truncated-sum answers,
  // breaking the monotonic-in-n assumption the solver depends on.
  if (halfLam > 500 && d2 > 4) {
    const mean = (d2 / (d2 - 2)) * ((d1 + lambda) / d1);
    const v =
      (2 *
        Math.pow(d2 / (d2 - 2), 2) *
        ((d1 + lambda) * (d1 + lambda) + (d1 + 2 * lambda) * (d2 - 2))) /
      (d1 * d1 * (d2 - 4));
    const sd = Math.sqrt(v);
    const z = (f - mean) / sd;
    if (z < -6) return 1;
    if (z > 6) return 0;
  }

  const jMode = Math.max(0, Math.floor(halfLam));
  // Widen the Poisson window for larger λ so we cover ±8σ of the mass.
  const maxSteps = Math.max(500, Math.ceil(8 * Math.sqrt(halfLam + 1)));

  function sfTerm(j) {
    const d1j = d1 + 2 * j;
    return fcdf_upper((f * d1) / d1j, d1j, d2);
  }

  let logPMode = -halfLam + (jMode > 0 ? jMode * Math.log(halfLam) - gammaln(jMode + 1) : 0);
  let pTerm = Math.exp(logPMode);
  let sum = pTerm * sfTerm(jMode);

  let pUp = pTerm;
  for (let j = jMode + 1; j < jMode + maxSteps; j++) {
    pUp *= halfLam / j;
    const contrib = pUp * sfTerm(j);
    sum += contrib;
    if (j - jMode > 10 && pUp < 1e-14) break;
  }

  let pDown = pTerm;
  for (let j = jMode - 1; j >= 0 && jMode - j < maxSteps; j--) {
    pDown *= (j + 1) / halfLam;
    const contrib = pDown * sfTerm(j);
    sum += contrib;
    if (jMode - j > 10 && pDown < 1e-14) break;
  }

  return Math.min(1, Math.max(0, sum));
}

// Noncentral chi-square CDF — Poisson mixture (starts at mode to avoid underflow)
function ncchi2cdf(x, k, lambda) {
  if (x <= 0) return 0;
  if (lambda <= 0) return chi2cdf(x, k);
  const halfLam = lambda / 2;
  // Large-λ short circuit: use normal approximation for the far tails.
  // Noncentral χ² has mean k+λ and variance 2(k+2λ); a |z|>6 tail is < 1e-9.
  if (halfLam > 500) {
    const mean = k + lambda;
    const sd = Math.sqrt(2 * (k + 2 * lambda));
    const z = (x - mean) / sd;
    if (z < -6) return 0;
    if (z > 6) return 1;
  }
  const jMode = Math.max(0, Math.floor(halfLam));
  // Poisson mixture width is √λ/2; widen the scan window with √halfLam so huge
  // λ doesn't silently truncate the sum (mirrors the ncf_sf fix).
  const maxSteps = Math.max(500, Math.ceil(8 * Math.sqrt(halfLam + 1)));

  function cdfTerm(j) {
    return gammainc(k / 2 + j, x / 2);
  }

  let logPMode = -halfLam + (jMode > 0 ? jMode * Math.log(halfLam) - gammaln(jMode + 1) : 0);
  let pTerm = Math.exp(logPMode);
  let sum = pTerm * cdfTerm(jMode);

  let pUp = pTerm;
  for (let j = jMode + 1; j < jMode + maxSteps; j++) {
    pUp *= halfLam / j;
    const contrib = pUp * cdfTerm(j);
    sum += contrib;
    if (j > jMode + 5 && pUp < 1e-14) break;
  }

  let pDown = pTerm;
  for (let j = jMode - 1; j >= 0; j--) {
    pDown *= (j + 1) / halfLam;
    const contrib = pDown * cdfTerm(j);
    sum += contrib;
    if (jMode - j > 5 && pDown < 1e-14) break;
  }

  return Math.min(1, Math.max(0, sum));
}

// ── 2. Generic helpers ──────────────────────────────────────────────────────

// Generic bisection solver: find x in [lo, hi] such that fn(x) ≈ target.
// Assumes fn is monotone non-decreasing. Returns NaN if target is not
// bracketed — this is intentional: silent clamping to a bracket boundary
// would let downstream code use a number that isn't actually a root. All
// existing callers are responsible for expanding hi (or shrinking lo)
// before delegating to bisect when their target might fall outside.
function bisect(fn, target, lo, hi, tol = 1e-6, maxIter = 200) {
  if (fn(lo) > target || fn(hi) < target) return NaN;
  for (let i = 0; i < maxIter; i++) {
    const mid = (lo + hi) / 2;
    if (fn(mid) < target) lo = mid;
    else hi = mid;
    if (hi - lo < tol) break;
  }
  return (lo + hi) / 2;
}

// ── 2b. Power functions ─────────────────────────────────────────────────────
// Keyed by test shape, same formulas used by tools/power.tsx. Kept here so
// the StatsTile (group plot) can report achieved power and the
// n-per-group needed for 80 % power directly from the observed data.

function powerTwoSample(d, n, alpha, tails) {
  const df = 2 * n - 2;
  const delta = d * Math.sqrt(n / 2);
  const tCrit = tinv(1 - alpha / tails, df);
  if (tails === 2) return 1 - nctcdf(tCrit, df, delta) + nctcdf(-tCrit, df, delta);
  return 1 - nctcdf(tCrit, df, delta);
}

function powerPaired(d, n, alpha, tails) {
  const df = n - 1;
  const delta = d * Math.sqrt(n);
  const tCrit = tinv(1 - alpha / tails, df);
  if (tails === 2) return 1 - nctcdf(tCrit, df, delta) + nctcdf(-tCrit, df, delta);
  return 1 - nctcdf(tCrit, df, delta);
}

function powerOneSample(d, n, alpha, tails) {
  return powerPaired(d, n, alpha, tails);
}

function powerAnova(f, n, alpha, k) {
  const df1 = k - 1,
    df2 = k * (n - 1);
  if (df2 < 1) return 0;
  const lambda = n * k * f * f;
  // Central F at small df has very heavy tails — e.g. F(1, 1) only reaches
  // p = 0.955 at x = 200 — so a fixed upper bracket of 200 silently clamps
  // fCrit for α ≤ 0.045 at (df1, df2) = (1, 1). Expand the bracket until it
  // covers 1 − α (20 doublings → ~2·10⁸, comfortably beyond any realistic
  // fCrit) before delegating to bisect. bisect itself now refuses on an
  // unbracketed target, so we propagate NaN when the expansion fails.
  let hi = 200;
  for (let i = 0; i < 20 && fcdf(hi, df1, df2) < 1 - alpha; i++) hi *= 2;
  const fCrit = bisect((x) => fcdf(x, df1, df2), 1 - alpha, 0, hi);
  if (!Number.isFinite(fCrit)) return NaN;
  return ncf_sf(fCrit, df1, df2, lambda);
}

function powerCorrelation(r, n, alpha, tails) {
  const zr = Math.atanh(r);
  const se = 1 / Math.sqrt(Math.max(1, n - 3));
  const zCrit = norminv(1 - alpha / tails);
  if (tails === 2) return normcdf(Math.abs(zr) / se - zCrit) + normcdf(-Math.abs(zr) / se - zCrit);
  return normcdf(zr / se - zCrit);
}

function powerChi2(w, n, alpha, df) {
  const lambda = n * w * w;
  const chiCrit = chi2inv(1 - alpha, df);
  return 1 - ncchi2cdf(chiCrit, df, lambda);
}

// Cohen's f for ANOVA from group means + pooled within-SD.
//
// f = σ_means / σ_within, where σ_means is the **population-style** SD of
// the group means — i.e. divides by k, not (k−1) — treating the supplied
// means as the entire population of cell means rather than a sample. This
// matches Cohen (1988) and R's pwr::pwr.anova.test, which is what the
// downstream power calculator is calibrated against. Callers that have a
// sample SD of group means should multiply by √((k−1)/k) before passing
// in, or recompute from the raw means.
function fFromGroupMeans(meansArr, sd) {
  if (!meansArr.length || sd <= 0) return 0;
  const grandMean = meansArr.reduce((a, b) => a + b, 0) / meansArr.length;
  const sigmaMeans = Math.sqrt(
    meansArr.reduce((s, m) => s + (m - grandMean) * (m - grandMean), 0) / meansArr.length
  );
  return sigmaMeans / sd;
}

// ──────────────────────────────────────────────────────────────────
// stats-tests.js
// ──────────────────────────────────────────────────────────────────
// stats-tests.js — descriptive helpers + parametric / nonparametric tests +
// effect sizes.
//
// Loaded after stats-dist.js (depends on its distribution / special functions).
// Plain script-mode JS like the rest of the stats-*.js files — top-level
// declarations stay as globals once the bundle is concatenated.
//
// Layout:
//   3. Sample helpers          — mean, variance, sd, rank-with-ties
//   4. Shapiro-Wilk normality  — Royston 1995, AS R94
//   5. Levene / Brown-Forsythe equal-variance test
//   6. Two-sample location     — t-test (Student / Welch), Mann-Whitney U
//   7. Two-sample effect sizes — Cohen's d, Hedges' g, rank-biserial
//   8. k-sample location       — one-way / Welch ANOVA, Kruskal-Wallis
//   9. Correlation             — Pearson r, Spearman ρ, Kendall τ-b,
//                                selectCorrelation auto-picker
//  10. k-sample effect sizes   — η², ε²

// ── 3. Sample helpers ───────────────────────────────────────────────────────

function sampleMean(x) {
  const n = x.length;
  if (n === 0) return NaN;
  let s = 0;
  for (let i = 0; i < n; i++) s += x[i];
  return s / n;
}

// Sample variance with (n-1) denominator (Bessel-corrected). Welford's
// online algorithm: one pass, no need to compute the mean separately, and
// numerically more robust than the naive E[X²] − E[X]² formula (which
// catastrophically cancels when the data have a large offset). The classic
// two-pass algorithm is comparable in accuracy on most inputs, but Welford
// avoids a second loop and pre-computed mean, which is cleaner and slightly
// faster on large arrays.
function sampleVariance(x) {
  const n = x.length;
  if (n < 2) return NaN;
  let mean = 0,
    M2 = 0;
  for (let i = 0; i < n; i++) {
    const d = x[i] - mean;
    mean += d / (i + 1);
    M2 += d * (x[i] - mean);
  }
  return M2 / (n - 1);
}

function sampleSD(x) {
  return Math.sqrt(sampleVariance(x));
}

// Midrank assignment with ties — returns ranks[i] = 1-based rank of x[i],
// averaging ranks for tied values. Also returns the sum of (t³−t)/12 for each
// tie group, needed as the tie-correction term in Mann-Whitney / Kruskal-Wallis.
function rankWithTies(x) {
  const n = x.length;
  const idx = x.map((v, i) => [v, i]).sort((a, b) => a[0] - b[0]);
  const ranks = new Array(n);
  let tieCorrection = 0;
  let i = 0;
  while (i < n) {
    let j = i;
    while (j + 1 < n && idx[j + 1][0] === idx[i][0]) j++;
    const avgRank = (i + j + 2) / 2; // 1-based average of ranks [i+1 .. j+1]
    for (let k = i; k <= j; k++) ranks[idx[k][1]] = avgRank;
    const t = j - i + 1;
    if (t > 1) tieCorrection += t * t * t - t;
    i = j + 1;
  }
  return { ranks, tieCorrection };
}

// ── 4. Normality: Shapiro-Wilk (Royston 1995, AS R94) ───────────────────────
//
// Algorithm AS R94 (Royston 1995), as implemented in R's stats::shapiro.test.
// Valid for 3 ≤ n ≤ 5000. Returns { W, p }.
//
// The W statistic:   W = (Σ a_i · x_(i))² / Σ (x_i − x̄)²
//
// Coefficients a_i are derived from the expected values of normal order
// statistics (approximated analytically here — exact values would require
// computing E[z_(i:n)] via numerical integration, but Royston's approximation
// is accurate to the W-statistic's precision).
//
// P-value transformation uses polynomial-in-log approximations tabulated by
// Royston for the normalizing transform of W.

function shapiroWilk(x) {
  const n = x.length;
  if (n < 3 || n > 5000) {
    return { W: NaN, p: NaN, error: "Shapiro-Wilk requires 3 ≤ n ≤ 5000" };
  }
  const sorted = [...x].sort((a, b) => a - b);

  // Expected values of normal order statistics via Blom's approximation:
  //   m_i ≈ Φ⁻¹((i − 3/8) / (n + 1/4))
  // These are the "m" vector in AS R94.
  const m = new Array(n);
  for (let i = 0; i < n; i++) {
    m[i] = norminv((i + 1 - 3 / 8) / (n + 1 / 4));
  }
  let mm = 0;
  for (let i = 0; i < n; i++) mm += m[i] * m[i];

  // Coefficients a_i (Royston 1992 analytical form, AS R94).
  // For i = n:    a_n   = −2.706056 u⁵ + 4.434685 u⁴ − 2.071190 u³
  //                       − 0.147981 u² + 0.221157 u + m_n / √mm
  // For i = n−1:  a_{n−1} = −3.582633 u⁵ + 5.682633 u⁴ − 1.752460 u³
  //                         − 0.293762 u² + 0.042981 u + m_{n−1} / √mm
  // where u = 1/√n. Middle coefficients follow AS R94's epsilon correction.
  const a = new Array(n);
  const u = 1 / Math.sqrt(n);
  const sqrtMm = Math.sqrt(mm);

  if (n === 3) {
    // Exact for n = 3: a_1 = √(1/2), a_3 = −a_1, a_2 = 0.
    a[0] = -Math.SQRT1_2;
    a[1] = 0;
    a[2] = Math.SQRT1_2;
  } else {
    const an =
      m[n - 1] / sqrtMm +
      0.221157 * u -
      0.147981 * u * u -
      2.07119 * u * u * u +
      4.434685 * u * u * u * u -
      2.706056 * u * u * u * u * u;
    a[n - 1] = an;
    a[0] = -an;

    if (n >= 6) {
      const an1 =
        m[n - 2] / sqrtMm +
        0.042981 * u -
        0.293762 * u * u -
        1.75246 * u * u * u +
        5.682633 * u * u * u * u -
        3.582633 * u * u * u * u * u;
      a[n - 2] = an1;
      a[1] = -an1;

      // Epsilon correction for middle coefficients (AS R94).
      const phi =
        (mm - 2 * m[n - 1] * m[n - 1] - 2 * m[n - 2] * m[n - 2]) /
        (1 - 2 * an * an - 2 * an1 * an1);
      const sqrtPhi = Math.sqrt(phi);
      for (let i = 2; i < n - 2; i++) a[i] = m[i] / sqrtPhi;
    } else {
      // n = 4 or 5: only tail coefficients, simpler correction.
      const phi = (mm - 2 * m[n - 1] * m[n - 1]) / (1 - 2 * an * an);
      const sqrtPhi = Math.sqrt(phi);
      for (let i = 1; i < n - 1; i++) a[i] = m[i] / sqrtPhi;
    }
  }

  // W = (Σ a_i · x_(i))² / Σ (x_i − x̄)²
  let xbar = 0;
  for (let i = 0; i < n; i++) xbar += sorted[i];
  xbar /= n;
  let num = 0,
    den = 0;
  for (let i = 0; i < n; i++) {
    num += a[i] * sorted[i];
    const d = sorted[i] - xbar;
    den += d * d;
  }
  if (den === 0) return { W: NaN, p: NaN, error: "Zero variance" };
  // Clamp to [0, 1] — floating-point can produce W = 1 + ε for a perfect
  // linear sample (e.g. n=3 [1,2,3]), which would break asin(√W) below.
  const W = Math.max(0, Math.min(1, (num * num) / den));

  // P-value via Royston 1995 normalizing transform.
  let p;
  if (n === 3) {
    // Exact distribution at n=3: p = 6 · (asin(√W) − asin(√(3/4))) / π
    const pi6 = 6 / Math.PI;
    const stqr = Math.asin(Math.sqrt(3 / 4));
    p = pi6 * (Math.asin(Math.sqrt(W)) - stqr);
    if (p < 0) p = 0;
    if (p > 1) p = 1;
  } else if (n <= 11) {
    // Polynomial in n for gamma and mu, log-transform on (gamma − ln(1−W)).
    const gamma = -2.273 + 0.459 * n;
    const mu = 0.544 - 0.39978 * n + 0.025054 * n * n - 0.0006714 * n * n * n;
    const sigma = Math.exp(1.3822 - 0.77857 * n + 0.062767 * n * n - 0.0020322 * n * n * n);
    const y = -Math.log(gamma - Math.log(1 - W));
    const z = (y - mu) / sigma;
    p = normsf(z);
  } else {
    // n ≥ 12: log(1−W) is approximately normal after transform.
    const lnN = Math.log(n);
    const mu = -1.5861 - 0.31082 * lnN - 0.083751 * lnN * lnN + 0.0038915 * lnN * lnN * lnN;
    const sigma = Math.exp(-0.4803 - 0.082676 * lnN + 0.0030302 * lnN * lnN);
    const y = Math.log(1 - W);
    const z = (y - mu) / sigma;
    p = normsf(z);
  }

  return { W, p };
}

// ── 5. Equal-variance tests ─────────────────────────────────────────────────
//
// Brown-Forsythe variant of Levene's test (median-based — robust to
// non-normality, which is what we want in a screening step that runs before
// we've decided whether the data are normal).
//
// Algorithm: for each group compute |x_ij − median_i|, then run a one-way
// ANOVA on those absolute deviations. F statistic and p-value from the
// F-distribution.
//
// Input: groups = [[x11, x12, ...], [x21, x22, ...], ...]
// Output: { F, df1, df2, p }

function leveneTest(groups) {
  const k = groups.length;
  if (k < 2) return { F: NaN, df1: 0, df2: 0, p: NaN, error: "≥2 groups required" };
  // Absolute deviations from the group median.
  const devs = groups.map((g) => {
    const s = [...g].sort((a, b) => a - b);
    const n = s.length;
    const med = n % 2 === 0 ? (s[n / 2 - 1] + s[n / 2]) / 2 : s[Math.floor(n / 2)];
    return g.map((v) => Math.abs(v - med));
  });
  // One-way ANOVA on deviations.
  let Ntot = 0;
  let grandSum = 0;
  for (const d of devs) {
    Ntot += d.length;
    for (const v of d) grandSum += v;
  }
  if (Ntot <= k) return { F: NaN, df1: 0, df2: 0, p: NaN, error: "Not enough observations" };
  const grandMean = grandSum / Ntot;
  let ssBetween = 0,
    ssWithin = 0;
  for (const d of devs) {
    const n = d.length;
    if (n === 0) continue;
    let s = 0;
    for (const v of d) s += v;
    const m = s / n;
    ssBetween += n * (m - grandMean) * (m - grandMean);
    for (const v of d) ssWithin += (v - m) * (v - m);
  }
  const df1 = k - 1;
  const df2 = Ntot - k;
  if (ssWithin === 0) {
    // All groups are internally constant → within-group dispersion is zero
    // and Levene's F is undefined (0/0 at best, a phantom ∞ at worst).
    // R's equivalent oneway.test on the deviations reports F = NaN / p = NA.
    return {
      F: NaN,
      df1,
      df2,
      p: NaN,
      error: "Data are essentially constant (zero within-group dispersion)",
    };
  }
  const F = ssBetween / df1 / (ssWithin / df2);
  const p = fcdf_upper(F, df1, df2);
  return { F, df1, df2, p };
}

// ── 6. Two-sample location tests ────────────────────────────────────────────
//
// tTest(x, y, { equalVar }) — two-sample t-test.
//   equalVar=true  → Student's t (pooled variance, df = n1+n2−2)
//   equalVar=false → Welch's t (unequal variance, Welch-Satterthwaite df)
// Two-sided p-value. Returns { t, df, p, mean1, mean2, ... }.

function tTest(x, y, opts = {}) {
  const equalVar = opts.equalVar !== false;
  const n1 = x.length,
    n2 = y.length;
  if (n1 < 2 || n2 < 2) {
    return { t: NaN, df: 0, p: NaN, error: "Each group needs n≥2" };
  }
  const m1 = sampleMean(x),
    m2 = sampleMean(y);
  const v1 = sampleVariance(x),
    v2 = sampleVariance(y);
  // Degenerate case: both groups constant. Matches R, which refuses with
  // "data are essentially constant" — any result here would have NaN df
  // (Welch) or zero SE (Student), neither of which is meaningful.
  if (v1 === 0 && v2 === 0) {
    return {
      t: NaN,
      df: NaN,
      p: NaN,
      mean1: m1,
      mean2: m2,
      var1: v1,
      var2: v2,
      n1,
      n2,
      error: "Data are essentially constant (zero variance in both groups)",
    };
  }
  let t, df;
  if (equalVar) {
    const sp2 = ((n1 - 1) * v1 + (n2 - 1) * v2) / (n1 + n2 - 2);
    const se = Math.sqrt(sp2 * (1 / n1 + 1 / n2));
    t = (m1 - m2) / se;
    df = n1 + n2 - 2;
  } else {
    const se = Math.sqrt(v1 / n1 + v2 / n2);
    t = (m1 - m2) / se;
    const num = (v1 / n1 + v2 / n2) ** 2;
    const den = (v1 / n1) ** 2 / (n1 - 1) + (v2 / n2) ** 2 / (n2 - 1);
    df = num / den;
  }
  // Two-sided p via tail-accurate upper helper (avoids 1 − (near-1) cancellation
  // that underflowed p to 0 at |t| > ~9).
  const p = 2 * tcdf_upper(Math.abs(t), df);
  return { t, df, p, mean1: m1, mean2: m2, var1: v1, var2: v2, n1, n2 };
}

// Mann-Whitney U test (two-sided) — ranks with midranks for ties, normal
// approximation with continuity correction and tie correction to σ_U².
// Matches R's wilcox.test(x, y, exact=FALSE, correct=TRUE) when there are
// ties or larger samples; R switches to an exact enumerator when n1*n2<50
// and there are no ties — we note this in comments but stick to normal
// approximation here (the error vs exact is <0.01 in p even for small n).
//
// Returns { U, U1, U2, z, p, n1, n2 }. U = min(U1, U2).

function mannWhitneyU(x, y) {
  const n1 = x.length,
    n2 = y.length;
  if (n1 < 1 || n2 < 1) return { U: NaN, z: NaN, p: NaN, error: "Empty group" };
  const all = x.concat(y);
  const { ranks, tieCorrection } = rankWithTies(all);
  let R1 = 0;
  for (let i = 0; i < n1; i++) R1 += ranks[i];
  const U1 = R1 - (n1 * (n1 + 1)) / 2;
  const U2 = n1 * n2 - U1;
  const U = Math.min(U1, U2);
  const N = n1 + n2;
  const muU = (n1 * n2) / 2;
  // σ_U² with tie correction (Lehmann 1975):
  //  σ² = n1·n2/12 · [(N+1) − Σ(t³−t) / (N(N−1))]
  const sigma2 = ((n1 * n2) / 12) * (N + 1 - tieCorrection / (N * (N - 1)));
  const sigmaU = Math.sqrt(sigma2);
  // Continuity-corrected z (matches wilcox.test correct=TRUE).
  // Shift U toward the mean by 0.5.
  const diff = U1 - muU;
  let z;
  if (sigmaU === 0) z = 0;
  else if (diff > 0) z = (diff - 0.5) / sigmaU;
  else if (diff < 0) z = (diff + 0.5) / sigmaU;
  else z = 0;
  // Tail-accurate normsf — survives |z| > ~7 where 1 − normcdf cancels to 0.
  const p = 2 * normsf(Math.abs(z));
  return { U, U1, U2, z, p, n1, n2 };
}

// ── 7. Two-sample effect sizes ──────────────────────────────────────────────
//
// Cohen's d — standardized mean difference using pooled SD (Bessel-corrected).
// Hedges' g — small-sample bias-corrected version of Cohen's d.
// rankBiserial — non-parametric effect size paired with Mann-Whitney U.

function cohenD(x, y) {
  const n1 = x.length,
    n2 = y.length;
  if (n1 < 2 || n2 < 2) return NaN;
  const m1 = sampleMean(x),
    m2 = sampleMean(y);
  const v1 = sampleVariance(x),
    v2 = sampleVariance(y);
  const sp2 = ((n1 - 1) * v1 + (n2 - 1) * v2) / (n1 + n2 - 2);
  // Pooled SD is zero → effect size is undefined (±Infinity is misleading).
  if (sp2 === 0) return NaN;
  return (m1 - m2) / Math.sqrt(sp2);
}

function hedgesG(x, y) {
  const d = cohenD(x, y);
  if (!Number.isFinite(d)) return d;
  const df = x.length + y.length - 2;
  if (df < 1) return NaN;
  // Exact small-sample correction factor:
  //   J(df) = Γ(df/2) / (Γ((df−1)/2) · √(df/2))
  // computed in log space via gammaln to avoid Γ overflow at large df.
  // The familiar `J ≈ 1 − 3/(4n − 9)` shortcut is the leading term of the
  // asymptotic expansion; it's off by ~0.3% at the smallest practical
  // sample (n1 = n2 = 3) and converges to the exact form by n ≈ 30.
  // Tightening this also matches what `effectsize::hedges_g()` reports.
  const J = Math.exp(gammaln(df / 2) - gammaln((df - 1) / 2) - 0.5 * Math.log(df / 2));
  return d * J;
}

// Rank-biserial correlation from Mann-Whitney U (Kerby 2014).
// r = 1 − 2U/(n1·n2). Sign follows U1 vs U2 (positive means x tends to rank
// higher than y).
function rankBiserial(U1, n1, n2) {
  if (n1 * n2 === 0) return NaN;
  return 1 - (2 * U1) / (n1 * n2);
}

// 95 % confidence interval for Cohen's d (or d_av) on two independent
// samples, using the noncentral-t pivot of Cumming & Finch 2001 ("A
// primer on the understanding, use, and calculation of confidence
// intervals that are based on central and noncentral distributions",
// Educational and Psychological Measurement 61(4)):
//
//   t_obs  = d / √(1/n1 + 1/n2)          observed t-statistic
//   df     = n1 + n2 − 2                 (Student-pooled df; we use the
//                                         same df for d_av as a working
//                                         approximation — Welch-Satterthwaite
//                                         df differs slightly but the CI
//                                         on d is dominated by t-quantile
//                                         scale, not by the df shift)
//
// Then bisect over the noncentrality parameter λ to find:
//   λ_lo such that P(T ≤ t_obs | df, ncp = λ_lo) = 1 − α/2
//   λ_hi such that P(T ≤ t_obs | df, ncp = λ_hi) = α/2
//
// `nctcdf(t, df, ncp)` is monotonically *decreasing* in ncp, so we
// bisect against `-nctcdf(...)` (monotone increasing — what `bisect`
// expects).
//
// Returns `{ lo, hi }` on success, `{ lo: NaN, hi: NaN }` when the
// inputs are degenerate (n < 2 or non-finite d). Default confidence
// 0.95; explicit `conf` parameter overrides.
function cohenDCI(d, n1, n2, conf) {
  const c = conf == null ? 0.95 : conf;
  if (!Number.isFinite(d) || n1 < 2 || n2 < 2 || c <= 0 || c >= 1) {
    return { lo: NaN, hi: NaN };
  }
  const alpha = 1 - c;
  const seFactor = Math.sqrt(1 / n1 + 1 / n2);
  const tObs = d / seFactor;
  const df = n1 + n2 - 2;
  // Bracket: ±|tObs| + 20 covers all practical d values (|d| up to ~10).
  const halfRange = Math.abs(tObs) + 20;
  const negNct = (lam) => -nctcdf(tObs, df, lam);
  const lambdaLo = bisect(negNct, -(1 - alpha / 2), -halfRange, halfRange);
  const lambdaHi = bisect(negNct, -alpha / 2, -halfRange, halfRange);
  if (!Number.isFinite(lambdaLo) || !Number.isFinite(lambdaHi)) {
    return { lo: NaN, hi: NaN };
  }
  return { lo: lambdaLo * seFactor, hi: lambdaHi * seFactor };
}

// ── 8. k-sample location tests ──────────────────────────────────────────────
//
// Input for all three is `groups` — an array of numeric arrays.

// One-way ANOVA (equal variances assumed).
// Returns { F, df1, df2, p, ssBetween, ssWithin, grandMean }.
function oneWayANOVA(groups) {
  const k = groups.length;
  if (k < 2) return { F: NaN, df1: 0, df2: 0, p: NaN, error: "≥2 groups required" };
  let Ntot = 0;
  let grandSum = 0;
  for (const g of groups) {
    Ntot += g.length;
    for (const v of g) grandSum += v;
  }
  if (Ntot <= k) return { F: NaN, df1: 0, df2: 0, p: NaN, error: "Not enough observations" };
  const grandMean = grandSum / Ntot;
  let ssBetween = 0,
    ssWithin = 0;
  for (const g of groups) {
    const n = g.length;
    if (n === 0) continue;
    let s = 0;
    for (const v of g) s += v;
    const m = s / n;
    ssBetween += n * (m - grandMean) * (m - grandMean);
    for (const v of g) ssWithin += (v - m) * (v - m);
  }
  const df1 = k - 1;
  const df2 = Ntot - k;
  if (ssWithin === 0) {
    // Every group is internally constant. R's oneway.test returns F = Inf
    // with p < 2.2e-16, but that's misleading in a UI — the "significance"
    // is a divide-by-zero artefact, not evidence of a real location shift.
    // Mirror the tTest convention and refuse.
    return {
      F: NaN,
      df1,
      df2,
      p: NaN,
      ssBetween,
      ssWithin,
      grandMean,
      error: "Data are essentially constant (zero within-group dispersion)",
    };
  }
  const F = ssBetween / df1 / (ssWithin / df2);
  const p = fcdf_upper(F, df1, df2);
  return { F, df1, df2, p, ssBetween, ssWithin, grandMean };
}

// Welch's ANOVA (unequal variances).
// Follows R's oneway.test(var.equal=FALSE) source:
//   w_i = n_i / s_i²,  W = Σ w_i,  m = Σ(w_i · mean_i)/W
//   num = Σ w_i (mean_i − m)² / (k − 1)
//   h   = Σ (1 − w_i/W)² / (n_i − 1)
//   den = 1 + 2(k − 2)/(k² − 1) · h
//   F   = num/den,  df1 = k−1,  df2 = (k² − 1) / (3 h)
function welchANOVA(groups) {
  const k = groups.length;
  if (k < 2) return { F: NaN, df1: 0, df2: 0, p: NaN, error: "≥2 groups required" };
  const ns = groups.map((g) => g.length);
  if (ns.some((n) => n < 2)) {
    return { F: NaN, df1: 0, df2: 0, p: NaN, error: "Each group needs n≥2" };
  }
  const means = groups.map(sampleMean);
  const vars = groups.map(sampleVariance);
  // Welch weights are n_i / s_i² — any zero-variance group makes its weight
  // infinite and poisons the whole computation (matches R oneway.test's
  // F = NaN, p = NA on constant data).
  if (vars.some((v) => v === 0)) {
    return {
      F: NaN,
      df1: k - 1,
      df2: NaN,
      p: NaN,
      error: "Data are essentially constant (zero variance in at least one group)",
    };
  }
  const w = vars.map((v, i) => ns[i] / v);
  const Wsum = w.reduce((a, b) => a + b, 0);
  const m = w.reduce((a, wi, i) => a + wi * means[i], 0) / Wsum;
  let num = 0;
  for (let i = 0; i < k; i++) num += w[i] * (means[i] - m) * (means[i] - m);
  num /= k - 1;
  let h = 0;
  for (let i = 0; i < k; i++) {
    const term = 1 - w[i] / Wsum;
    h += (term * term) / (ns[i] - 1);
  }
  const den = 1 + ((2 * (k - 2)) / (k * k - 1)) * h;
  const F = num / den;
  const df1 = k - 1;
  const df2 = (k * k - 1) / (3 * h);
  const p = fcdf_upper(F, df1, df2);
  return { F, df1, df2, p };
}

// Kruskal-Wallis H test with tie correction.
//   H = (12/(N(N+1))) · Σ (R_i²/n_i) − 3(N+1)
//   H' = H / (1 − Σ(t³−t)/(N³−N))       [tie-corrected]
//   df = k − 1
//   p  = 1 − χ²_df(H')
function kruskalWallis(groups) {
  const k = groups.length;
  if (k < 2) return { H: NaN, df: 0, p: NaN, error: "≥2 groups required" };
  // Concatenate, remember group membership, rank together.
  const all = [];
  const owner = [];
  for (let i = 0; i < k; i++) {
    for (const v of groups[i]) {
      all.push(v);
      owner.push(i);
    }
  }
  const N = all.length;
  if (N <= k) return { H: NaN, df: 0, p: NaN, error: "Not enough observations" };
  // All values identical → ranks are all (N+1)/2, H computes to 0/0, and the
  // tie-correction denominator C = 1 − (N³−N)/(N³−N) = 0. The naive code path
  // skipped the divide and reported H=0, p=1 — a "no difference detected"
  // answer that masks the fact that the test is undefined. Match R's
  // kruskal.test behavior (it warns and returns NaN) by detecting the
  // all-tied case explicitly and surfacing an error the stats tile picks up.
  let allTied = true;
  for (let i = 1; i < N; i++) {
    if (all[i] !== all[0]) {
      allTied = false;
      break;
    }
  }
  if (allTied) {
    return { H: NaN, df: k - 1, p: NaN, error: "Data are essentially constant" };
  }
  const { ranks, tieCorrection } = rankWithTies(all);
  // Sum of ranks per group.
  const R = new Array(k).fill(0);
  for (let i = 0; i < N; i++) R[owner[i]] += ranks[i];
  let sumR2n = 0;
  for (let i = 0; i < k; i++) sumR2n += (R[i] * R[i]) / groups[i].length;
  let H = (12 / (N * (N + 1))) * sumR2n - 3 * (N + 1);
  // Tie correction (Siegel & Castellan): divide H by C.
  const C = 1 - tieCorrection / (N * N * N - N);
  if (C > 0) H /= C;
  const df = k - 1;
  const p = 1 - chi2cdf(H, df);
  return { H, df, p };
}

// ── 9. Correlation (paired bivariate) ──────────────────────────────────────
//
// Pearson r, Spearman ρ, Kendall τ-b. Used by the scatter tool's stats
// panel.
//
// Each returns `{ <coef>, p, n, ci?, error? }` with `<coef>` named after the
// estimator (`r` / `rho` / `tau`). Inputs are paired arrays of equal length;
// rows where either value is non-finite are dropped (matches R's
// `cor.test`'s `complete.obs` default).
//
// Notation: `S2x = Σ (x − x̄)²`, `S2y = Σ (y − ȳ)²`, `Sxy = Σ (x − x̄)(y − ȳ)`.

// Drop rows with non-finite x or y; return the cleaned pair.
function _pairwiseComplete(x, y) {
  const n = Math.min(x.length, y.length);
  const xs = [];
  const ys = [];
  for (let i = 0; i < n; i++) {
    const xv = x[i],
      yv = y[i];
    if (Number.isFinite(xv) && Number.isFinite(yv)) {
      xs.push(xv);
      ys.push(yv);
    }
  }
  return { xs, ys, n: xs.length };
}

// Pearson product-moment correlation. Two-sided p via t-distribution with
// df = n−2. Fisher z transform CI: z = atanh(r); SE(z) = 1/√(n−3); back-
// transform with tanh. Confidence level via `opts.conf` (default 0.95).
//
// Returns `{ r, t, df, p, n, ci: { lo, hi } }`. Degenerate cases:
//   - n < 3                       → error "need ≥3 complete pairs"
//   - either axis zero-variance   → error "data are essentially constant"
//   - |r| = 1 (perfect fit)       → ci is { lo: ±1, hi: ±1 } and p is 0
function pearsonCorrelation(x, y, opts = {}) {
  const { xs, ys, n } = _pairwiseComplete(x, y);
  if (n < 3) {
    return { r: NaN, t: NaN, df: 0, p: NaN, n, error: "Need ≥3 complete pairs" };
  }
  const mx = sampleMean(xs);
  const my = sampleMean(ys);
  let S2x = 0,
    S2y = 0,
    Sxy = 0;
  for (let i = 0; i < n; i++) {
    const dx = xs[i] - mx;
    const dy = ys[i] - my;
    S2x += dx * dx;
    S2y += dy * dy;
    Sxy += dx * dy;
  }
  if (S2x === 0 || S2y === 0) {
    return {
      r: NaN,
      t: NaN,
      df: n - 2,
      p: NaN,
      n,
      error: "Data are essentially constant (zero variance in x or y)",
    };
  }
  let r = Sxy / Math.sqrt(S2x * S2y);
  // Clamp FP overshoot so atanh stays finite at the perfect-fit boundary.
  if (r > 1) r = 1;
  if (r < -1) r = -1;
  const df = n - 2;
  // Fisher z CI. At |r| = 1 atanh blows up to ±Inf — that's the right answer
  // (the CI collapses to a point), and Math.tanh of ±Inf gives ±1.
  const conf = opts.conf == null ? 0.95 : opts.conf;
  const ci = { lo: NaN, hi: NaN };
  if (n >= 4) {
    const z = Math.atanh(r);
    const se = 1 / Math.sqrt(n - 3);
    const zcrit = norminv(1 - (1 - conf) / 2);
    ci.lo = Math.tanh(z - zcrit * se);
    ci.hi = Math.tanh(z + zcrit * se);
  }
  // t-statistic + two-sided p. |r| = 1 → t = ±Inf → p = 0 (via tcdf_upper).
  const oneMinusR2 = Math.max(0, 1 - r * r);
  const t = oneMinusR2 === 0 ? (r > 0 ? Infinity : -Infinity) : r * Math.sqrt(df / oneMinusR2);
  const p = oneMinusR2 === 0 ? 0 : 2 * tcdf_upper(Math.abs(t), df);
  return { r, t, df, p, n, ci };
}

// Spearman rank correlation. Pearson of the midranks of x and y (so ties
// average their ranks — matches R's `cor(..., method = "spearman")` with
// the default `use = "everything"` on complete cases).
//
// P-value: t-approximation with df = n − 2 (matches R's
// `cor.test(..., method = "spearman", exact = FALSE)`).
//
// CI: Bonett & Wright (2000) Fisher-z variant —
//     SE(z) = √((1 + ρ̂²/2) / (n − 3))
//     z = atanh(ρ̂),  CI(ρ) = tanh(z ± z_{1−α/2} · SE(z))
// More accurate than naïve Pearson Fisher-z when ρ ≠ 0 because the variance
// of atanh(r_s) inflates with the magnitude of the underlying correlation.
function spearmanCorrelation(x, y, opts = {}) {
  const { xs, ys, n } = _pairwiseComplete(x, y);
  if (n < 3) {
    return { rho: NaN, t: NaN, df: 0, p: NaN, n, error: "Need ≥3 complete pairs" };
  }
  const { ranks: rx } = rankWithTies(xs);
  const { ranks: ry } = rankWithTies(ys);
  // Reuse the Pearson implementation on the rank vectors.
  const pearsonOnRanks = pearsonCorrelation(rx, ry, opts);
  if (pearsonOnRanks.error) {
    return { rho: NaN, t: NaN, df: n - 2, p: NaN, n, error: pearsonOnRanks.error };
  }
  const rho = pearsonOnRanks.r;
  const df = n - 2;
  const oneMinusRho2 = Math.max(0, 1 - rho * rho);
  const t = oneMinusRho2 === 0 ? (rho > 0 ? Infinity : -Infinity) : rho * Math.sqrt(df / oneMinusRho2);
  const p = oneMinusRho2 === 0 ? 0 : 2 * tcdf_upper(Math.abs(t), df);
  const conf = opts.conf == null ? 0.95 : opts.conf;
  const ci = { lo: NaN, hi: NaN };
  if (n >= 4) {
    const z = Math.atanh(rho);
    const se = Math.sqrt((1 + (rho * rho) / 2) / (n - 3));
    const zcrit = norminv(1 - (1 - conf) / 2);
    ci.lo = Math.tanh(z - zcrit * se);
    ci.hi = Math.tanh(z + zcrit * se);
  }
  return { rho, t, df, p, n, ci };
}

// Kendall τ-b (the tie-corrected variant) — equivalent to R's
// `cor.test(method = "kendall")` τ. Computed by direct O(n²) pair
// enumeration:
//
//     S = Σ_{i<j} sign(x_j − x_i) · sign(y_j − y_i)
//     τ = S / √((n0 − n1)(n0 − n2))
//
// where n0 = n(n−1)/2, n1 = Σ t_x·(t_x−1)/2 (pairs tied in x), and
// n2 = Σ t_y·(t_y−1)/2 (pairs tied in y).
//
// P-value: large-sample normal approximation with continuity correction
// (matches `cor.test(method = "kendall", exact = FALSE)`):
//
//     Var(S) = [n(n−1)(2n+5)
//              − Σ t_x(t_x−1)(2t_x+5) − Σ t_y(t_y−1)(2t_y+5)] / 18
//            + [Σ t_x(t_x−1)(t_x−2)] · [Σ t_y(t_y−1)(t_y−2)]
//                / (9 n(n−1)(n−2))
//            + [Σ t_x(t_x−1)] · [Σ t_y(t_y−1)] / (2 n(n−1))
//     z = S / √Var(S)               (no continuity correction —
//                                    matches R's cor.test source)
//
// No CI: an analytic CI on τ requires bootstrap or a Kendall-specific
// large-sample variance approximation (Long & Cliff 1997) that's only
// accurate when there are no ties. Stats panel surfaces τ + p + n.
function kendallTau(x, y, opts = {}) {
  // `opts` reserved for future use (e.g. an `exact: true` switch).
  void opts;
  const { xs, ys, n } = _pairwiseComplete(x, y);
  if (n < 3) {
    return { tau: NaN, z: NaN, p: NaN, n, S: 0, error: "Need ≥3 complete pairs" };
  }
  let S = 0;
  for (let i = 0; i < n - 1; i++) {
    const xi = xs[i],
      yi = ys[i];
    for (let j = i + 1; j < n; j++) {
      const dx = xs[j] - xi;
      const dy = ys[j] - yi;
      if (dx === 0 || dy === 0) continue;
      S += dx > 0 === dy > 0 ? 1 : -1;
    }
  }
  // Tie group sizes on each axis.
  const tieGroups = (arr) => {
    const sorted = arr.slice().sort((a, b) => a - b);
    const groups = [];
    let i = 0;
    while (i < n) {
      let j = i;
      while (j + 1 < n && sorted[j + 1] === sorted[i]) j++;
      const t = j - i + 1;
      if (t > 1) groups.push(t);
      i = j + 1;
    }
    return groups;
  };
  const tx = tieGroups(xs);
  const ty = tieGroups(ys);
  const sumPairs = (g) => g.reduce((s, t) => s + (t * (t - 1)) / 2, 0);
  const n0 = (n * (n - 1)) / 2;
  const n1 = sumPairs(tx);
  const n2 = sumPairs(ty);
  if (n0 - n1 <= 0 || n0 - n2 <= 0) {
    return {
      tau: NaN,
      z: NaN,
      p: NaN,
      n,
      S,
      error: "Data are essentially constant (all ties in x or y)",
    };
  }
  const tau = S / Math.sqrt((n0 - n1) * (n0 - n2));
  // Var(S) — three-term formula with tie corrections.
  let varS = (n * (n - 1) * (2 * n + 5)) / 18;
  for (const t of tx) varS -= (t * (t - 1) * (2 * t + 5)) / 18;
  for (const t of ty) varS -= (t * (t - 1) * (2 * t + 5)) / 18;
  if (tx.length && ty.length && n >= 3) {
    const sx3 = tx.reduce((s, t) => s + t * (t - 1) * (t - 2), 0);
    const sy3 = ty.reduce((s, t) => s + t * (t - 1) * (t - 2), 0);
    varS += (sx3 * sy3) / (9 * n * (n - 1) * (n - 2));
    const sx2 = tx.reduce((s, t) => s + t * (t - 1), 0);
    const sy2 = ty.reduce((s, t) => s + t * (t - 1), 0);
    varS += (sx2 * sy2) / (2 * n * (n - 1));
  }
  if (varS <= 0) {
    return { tau, z: NaN, p: NaN, n, S };
  }
  const z = S / Math.sqrt(varS);
  const p = 2 * normsf(Math.abs(z));
  return { tau, z, p, n, S };
}

// Diagnostic + recommendation for a paired scatter dataset (analogue of
// `selectTest` for k-group data). Returns:
//
//   { n, normality: [{ axis, n, W, p, normal, note? }, ...],
//     allNormal, recommendation: { test, reason }, suggestion? }
//
// Default pick is Pearson. If Shapiro-Wilk on either axis flags non-normal
// (alpha = 0.05) or n < 10, surface a Spearman suggestion; if the data are
// also small (n ≤ 30) or heavily-tied, suggest Kendall τ as the secondary
// alternative. The recommendation itself never changes — same UI contract
// as `selectTest`: it's a default the user can override from the panel's
// per-test dropdown.
function selectCorrelation(x, y, opts = {}) {
  const alphaN = opts.alphaNormality != null ? opts.alphaNormality : 0.05;
  const { xs, ys, n } = _pairwiseComplete(x, y);
  if (n < 3) {
    return {
      n,
      normality: [],
      allNormal: false,
      recommendation: { test: "pearson", reason: "Need ≥3 complete pairs to test a correlation." },
    };
  }
  const swCheck = (arr, axis) => {
    if (arr.length < 3) {
      return { axis, n: arr.length, W: null, p: null, normal: null, note: "n<3" };
    }
    const sw = shapiroWilk(arr);
    if (sw.error) {
      return { axis, n: arr.length, W: null, p: null, normal: null, note: sw.error };
    }
    return { axis, n: arr.length, W: sw.W, p: sw.p, normal: sw.p >= alphaN };
  };
  const normality = [swCheck(xs, "x"), swCheck(ys, "y")];
  const allKnownNormal = normality.every((r) => r.normal === true);
  const flagged = normality.filter((r) => r.normal === false);
  const test = "pearson";
  const baseDefault =
    "Default pick: Pearson product-moment correlation. Pearson is the most powerful test when both axes are approximately normal; Spearman and Kendall stay available as rank-based alternatives.";
  const swNarrative = (() => {
    if (flagged.length === 0 && allKnownNormal) {
      return `Shapiro-Wilk did not reject normality on x or y at α = ${alphaN}.`;
    }
    if (flagged.length > 0) {
      const labels = flagged
        .map((r) => `${r.axis} (W=${r.W.toFixed(3)}, p=${formatP(r.p)})`)
        .join(", ");
      return `Shapiro-Wilk flagged ${labels} as non-normal at α = ${alphaN}.`;
    }
    return "Shapiro-Wilk could not run on one or both axes (n < 3).";
  })();
  let suggestion = null;
  let suggestionNarrative = "";
  if (flagged.length > 0) {
    suggestion = {
      test: "spearman",
      reason:
        "Shapiro-Wilk flagged at least one axis as non-normal. Spearman ranks both axes before correlating, which is more robust to heavy tails and outliers than Pearson.",
    };
    suggestionNarrative =
      " If the non-normality looks substantive (heavy tails, strong skew, ordinal data), consider switching to Spearman ρ from the test dropdown; for very small or heavily-tied samples Kendall τ-b is a further alternative.";
  }
  const overrideHint =
    " You can override this pick from the stats panel's per-test dropdown; the trace below shows the diagnostics the recommendation is based on.";
  const out = {
    n,
    normality,
    allNormal: allKnownNormal,
    recommendation: { test, reason: `${baseDefault} ${swNarrative}${suggestionNarrative}${overrideHint}` },
  };
  if (suggestion) out.suggestion = suggestion;
  return out;
}

// ── 10. k-sample effect sizes ────────────────────────────────────────────────

// η² = SSbetween / SStotal (ANOVA).
function etaSquared(groups) {
  const a = oneWayANOVA(groups);
  if (a.error) return NaN;
  const ssTotal = a.ssBetween + a.ssWithin;
  return ssTotal === 0 ? 0 : a.ssBetween / ssTotal;
}

// ε² = H / (N − 1)  — Kruskal-Wallis effect size (Tomczak & Tomczak 2014).
function epsilonSquared(groups) {
  const kw = kruskalWallis(groups);
  if (kw.error) return NaN;
  let N = 0;
  for (const g of groups) N += g.length;
  return N > 1 ? kw.H / (N - 1) : NaN;
}

// ──────────────────────────────────────────────────────────────────
// stats-posthoc.js
// ──────────────────────────────────────────────────────────────────
// stats-posthoc.js — studentized-range distribution, all-pairs post-hocs,
// p-adjust, compact-letter-display, and the auto test-picker (`selectTest`).
//
// Loaded after stats-tests.js (depends on `oneWayANOVA`, `sampleMean`,
// `leveneTest`, `shapiroWilk`, etc.).
//
// Layout:
//   10. Studentized range distribution — _wprob, ptukey, qtukey
//   11. Post-hoc tests                  — Tukey HSD, Games-Howell, Dunn, BH
//   12. Compact letter display
//   13. Automatic test selection        — selectTest, pStars, formatP

// ── 10. Studentized range distribution ─────────────────────────────────────
//
// The CDF of the studentized range Q (k means, ν error df) is
//
//   P(Q ≤ q) = ∫₀^∞ f_S(s) · P(R ≤ q·s) ds
//
// where S = √(χ²_ν/ν) and R is the range of k independent standard normals.
// The range CDF itself is
//
//   P(R ≤ w) = ∫_{−∞}^{∞} k · φ(u) · [Φ(u+w) − Φ(u)]^{k−1} du
//
// Both integrals are handled by the cached 48-point Gauss-Legendre rule.
// Matches R's `ptukey` to ~5 decimal places on the cases we benchmark.

// P(range of k standard normals > w). Tail-accurate companion to `_wprob`,
// needed to compute ptukey's upper tail without the `1 − (near-1)` collapse
// that produced the old ~2e-10 floor in Tukey HSD / Games-Howell p-values.
//
// Derivation:
//   1 − F_R(w) = k·∫ φ(u)·[normsf(u)^{k−1} − d(u,w)^{k−1}] du   (with `d(u,w) = Φ(u+w) − Φ(u)`)
// is the identity `1 − F_R = 1 − F_R` once you substitute `1 = k·∫ φ·normsf^{k-1}`,
// but the INTEGRAND factorises without cancellation:
//   a^{k-1} − b^{k-1} = (a − b) · Σ_{j=0}^{k-2} a^{k-2-j}·b^j
// where a = normsf(u), b = d(u,w), and crucially a − b = normsf(u+w) —
// computed as a single tail-accurate call, not as a subtraction of two
// near-1 floats. Every factor on the right is a manifest non-negative.
function _wprob_upper(w, k) {
  if (w <= 0) return 1;
  const gl = _gaussLegendre(48);
  // The integrand `k·φ(u)·normsf(u+w)·Σ…` peaks at u = −w/2 (balance of
  // φ(u) → 0 rightward vs normsf(u+w) → 0 leftward). For w > ~16 that peak
  // escapes a fixed [−8, 8] window, and our estimate under-counts by many
  // orders of magnitude. Centre the 48-node rule on the peak with width ±8σ
  // so the peak and its gaussian decay are always sampled — but keep the
  // window covering u = 0 ±8 for small w so the far-right tail stays in.
  const peak = -w / 2;
  const lo = Math.min(-8, peak - 8);
  const hi = Math.max(8, peak + 8);
  const half = (hi - lo) / 2,
    mid = (hi + lo) / 2;
  const invSqrt2Pi = 1 / Math.sqrt(2 * Math.PI);
  let sum = 0;
  for (let i = 0; i < 48; i++) {
    const u = mid + half * gl.nodes[i];
    const phiU = invSqrt2Pi * Math.exp(-0.5 * u * u);
    const a = normsf(u);
    const aMinusB = normsf(u + w); // = a − b, direct (no cancellation)
    if (a <= 0 || aMinusB <= 0) continue;
    const b = a - aMinusB;
    // Σ_{j=0}^{k-2} a^{k-2-j} · b^j
    let geoSum = 0;
    let term = Math.pow(a, k - 2);
    const ratio = b / a;
    for (let j = 0; j < k - 1; j++) {
      geoSum += term;
      term *= ratio;
    }
    const integrand = k * phiU * aMinusB * geoSum;
    sum += half * gl.weights[i] * integrand;
  }
  return Math.max(0, Math.min(1, sum));
}

// P(range of k standard normals ≤ w). The inner difference Φ(u+w) − Φ(u) is
// the source of the old ~2e-10 ptukey floor: for u > 0 and u+w both large,
// subtracting `1 − tiny` from `1 − tiny′` kills precision. We branch so each
// regime uses whichever of normcdf / normsf stays on the small side.
function _wprob(w, k) {
  if (w <= 0) return 0;
  const gl = _gaussLegendre(48);
  // Truncate at ±8σ — φ is negligible beyond.
  const lo = -8,
    hi = 8;
  const half = (hi - lo) / 2,
    mid = (hi + lo) / 2;
  const invSqrt2Pi = 1 / Math.sqrt(2 * Math.PI);
  let sum = 0;
  for (let i = 0; i < 48; i++) {
    const u = mid + half * gl.nodes[i];
    const phiU = invSqrt2Pi * Math.exp(-0.5 * u * u);
    let diff;
    if (u >= 0) {
      // Both args ≥ u ≥ 0 → both in the upper tail. normsf stays accurate.
      diff = normsf(u) - normsf(u + w);
    } else if (u + w <= 0) {
      // Both args ≤ 0 → lower tail; normcdf stays accurate.
      diff = normcdf(u + w) - normcdf(u);
    } else {
      // u < 0 < u+w — straddles 0; subtraction is numerically safe.
      diff = normcdf(u + w) - normcdf(u);
    }
    if (diff <= 0) continue;
    const term = k * phiU * Math.pow(diff, k - 1);
    sum += half * gl.weights[i] * term;
  }
  return Math.max(0, Math.min(1, sum));
}

// P(Q ≤ q | k groups, df error degrees of freedom)
//
// Substitute y = log(s) — integrate f_S(e^y)·e^y dy. Integration bounds
// [yLo, yHi] are set by the chi² quantiles so the support is exactly where
// the mass lives. This keeps the 48 Gauss-Legendre nodes concentrated on the
// peak regardless of df (a fixed s = u/(1−u) map leaks nodes into the
// exponential tail at high df, saturating ptukey well below 1).
function ptukey(q, k, df) {
  if (q <= 0) return 0;
  if (k < 2 || df < 1) return NaN;
  const gl = _gaussLegendre(48);
  // S = √(χ²_ν / ν). Bound y = log(S) via chi² quantiles at ±1e-10.
  const chiLo = chi2inv(1e-10, df);
  const chiHi = chi2inv(1 - 1e-10, df);
  const yLo = 0.5 * Math.log(Math.max(chiLo, 1e-300) / df);
  const yHi = 0.5 * Math.log(chiHi / df);
  const halfDf = df / 2;
  const logConst = Math.log(2) + halfDf * Math.log(halfDf) - gammaln(halfDf);
  const halfW = (yHi - yLo) / 2;
  const midW = (yHi + yLo) / 2;
  let sum = 0;
  for (let i = 0; i < 48; i++) {
    const y = midW + halfW * gl.nodes[i];
    const s = Math.exp(y);
    // f_S(s) · ds = 2·(ν/2)^(ν/2)/Γ(ν/2) · s^(ν−1) · exp(−ν·s²/2) · s dy
    const logFS = logConst + df * y - (df * s * s) / 2;
    const fSds = Math.exp(logFS);
    if (!Number.isFinite(fSds) || fSds === 0) continue;
    sum += halfW * gl.weights[i] * fSds * _wprob(q * s, k);
  }
  return Math.max(0, Math.min(1, sum));
}

// P(Q > q | k groups, df error degrees of freedom). Tail-accurate counterpart
// to `ptukey`: shares the same outer structure but passes `_wprob_upper`
// through the Gauss-Legendre integrator so the result never goes through a
// `1 − (near-1)` subtraction. Callers that want the upper tail of Tukey HSD
// or Games-Howell p-values use this instead of `1 - ptukey(...)`.
function ptukey_upper(q, k, df) {
  if (q <= 0) return 1;
  if (k < 2 || df < 1) return NaN;
  const gl = _gaussLegendre(48);
  const chiLo = chi2inv(1e-10, df);
  const chiHi = chi2inv(1 - 1e-10, df);
  const yLo = 0.5 * Math.log(Math.max(chiLo, 1e-300) / df);
  const yHi = 0.5 * Math.log(chiHi / df);
  const halfDf = df / 2;
  const logConst = Math.log(2) + halfDf * Math.log(halfDf) - gammaln(halfDf);
  const halfW = (yHi - yLo) / 2;
  const midW = (yHi + yLo) / 2;
  let sum = 0;
  for (let i = 0; i < 48; i++) {
    const y = midW + halfW * gl.nodes[i];
    const s = Math.exp(y);
    const logFS = logConst + df * y - (df * s * s) / 2;
    const fSds = Math.exp(logFS);
    if (!Number.isFinite(fSds) || fSds === 0) continue;
    sum += halfW * gl.weights[i] * fSds * _wprob_upper(q * s, k);
  }
  return Math.max(0, Math.min(1, sum));
}

// Inverse of the studentized range CDF: find q such that ptukey(q, k, df) = p.
// Historically this called bisect(…, 0.01, 100) with a fixed upper bracket,
// which clamped silently for extreme inputs (e.g. k = 50, df = 1, p = 0.999).
// Now expands the upper bracket by doubling until it covers p, then bisects
// with a relative-tolerance termination so the precision is consistent
// regardless of the answer's magnitude. Returns NaN when the expansion
// cannot bracket p — matches R qtukey's NaN-with-warning behavior at
// pathological inputs rather than returning a stale bracket boundary.
//
// Design envelope (verified against SciPy `studentized_range.ppf` in
// `benchmark/run-scipy.py` and tracked by `isQtukeyPathological` in
// `benchmark/run-scipy.js`):
//
//   Pass-band  — df ≥ 3, or (df ∈ {1, 2} with p < 0.95) or k < 10.
//                Within 5 % relative of SciPy across the (p, k, df) grid.
//   Pathological — df ≤ 2 ∧ p ≥ 0.95 ∧ k ≥ 10.
//                The R / SciPy reference itself diverges from
//                Monte-Carlo by single-digit percent in this regime,
//                so cross-validation falls back to a "documented
//                disagreement" bucket rather than a CI-fail.
//
// Caller responsibility: when (1−α, k, df) lies in the pathological
// envelope, downstream consumers (`tukeyHSD`'s CI bounds, …) should
// surface a methodological warning so users know the derived CI is
// only accurate to ~5 %. See the `warning` field on `tukeyHSD`'s
// return for the canonical pattern. NaN is a separate (currently
// unreachable in practice) failure mode for k / df with p so close
// to 1 that even 20 doublings don't cover it — also handled by the
// same `warning` channel.
function qtukey(p, k, df) {
  if (p <= 0) return 0;
  if (p >= 1) return Infinity;
  if (k < 2 || df < 1) return NaN;
  let lo = 0.01,
    hi = 100;
  // 20 doublings cap hi at ~10⁸ — beyond any realistic (k, df, α) combo;
  // anything that doesn't fit is in the pathological envelope above.
  for (let i = 0; i < 20 && ptukey(hi, k, df) < p; i++) {
    lo = hi;
    hi *= 2;
  }
  if (ptukey(hi, k, df) < p) return NaN;
  for (let i = 0; i < 200; i++) {
    const mid = (lo + hi) / 2;
    if (ptukey(mid, k, df) < p) lo = mid;
    else hi = mid;
    if (hi - lo < 1e-7 * (Math.abs(lo) + 1)) break;
  }
  return (lo + hi) / 2;
}

// ── 11. Post-hoc tests ──────────────────────────────────────────────────────

// Tukey HSD — all pairwise comparisons following one-way ANOVA.
// Uses Tukey-Kramer for unbalanced designs.
//   q_ij = |m_i − m_j| / √(MSE · (1/n_i + 1/n_j) / 2)
//   p_ij = 1 − ptukey(q_ij, k, df_error)
//   CI half-width = qtukey(1−α, k, df_error) · √(MSE · (1/n_i + 1/n_j) / 2)
// Returns { pairs: [{ i, j, diff, se, q, p, lwr, upr }], k, df }
function tukeyHSD(groups, opts = {}) {
  const alpha = opts.alpha != null ? opts.alpha : 0.05;
  const k = groups.length;
  if (k < 2) return { pairs: [], error: "≥2 groups required" };
  const anova = oneWayANOVA(groups);
  if (anova.error) return { pairs: [], error: anova.error };
  const dfErr = anova.df2;
  const mse = anova.ssWithin / dfErr;
  // Degenerate case: every group is perfectly constant → MSE=0 → division
  // by zero in q. Refuse rather than emit Infinity q / zero p-values.
  if (mse === 0) {
    return {
      pairs: [],
      k,
      df: dfErr,
      mse,
      error: "Cannot compute Tukey HSD — zero within-group variance (data essentially constant)",
    };
  }
  const means = groups.map(sampleMean);
  const ns = groups.map((g) => g.length);
  const qCrit = qtukey(1 - alpha, k, dfErr);
  // Surface a methodological warning when (1−α, k, dfErr) sits inside
  // qtukey's documented pathological envelope (df ≤ 2 ∧ 1−α ≥ 0.95 ∧
  // k ≥ 10). The bracket-doubling expansion still finds a finite root,
  // but `benchmark/run-scipy.py` cross-checks against SciPy's
  // `studentized_range.ppf` and treats up to 5 % relative disagreement
  // there as expected — see `isQtukeyPathological` in
  // `benchmark/run-scipy.js`. p-values use `ptukey_upper` (no bracket
  // expansion involved) and stay reliable; only the per-pair lwr / upr
  // are approximate in that corner. The `qCrit` NaN check is a
  // belt-and-suspenders fallback for the (currently unreachable in
  // practice) case where even 20 doublings of hi don't cover p.
  const inPathologicalEnvelope = dfErr <= 2 && 1 - alpha >= 0.95 && k >= 10;
  let qCritWarning = null;
  if (!Number.isFinite(qCrit)) {
    qCritWarning = `Tukey HSD CI bounds unavailable — qtukey(${1 - alpha}, k=${k}, df=${dfErr}) returned NaN (outside the bracket-expansion envelope). p-values are still reliable; the per-pair lwr / upr are NaN.`;
  } else if (inPathologicalEnvelope) {
    qCritWarning = `Tukey HSD CI bounds approximate — qtukey(${1 - alpha}, k=${k}, df=${dfErr}) lies in the studentized-range design envelope (df ≤ 2 with k ≥ 10 at 1−α ≥ 0.95), where the reference (R, SciPy) disagree by ~5 % with each other. p-values stay reliable; the per-pair lwr / upr are accurate to within ~5 %. Consider Games-Howell (Welch-aware, less sensitive to small df) if this matches your real data.`;
  }
  const pairs = [];
  for (let i = 0; i < k - 1; i++) {
    for (let j = i + 1; j < k; j++) {
      const diff = means[j] - means[i];
      const se = Math.sqrt((mse * (1 / ns[i] + 1 / ns[j])) / 2);
      const q = Math.abs(diff) / se;
      const p = ptukey_upper(q, k, dfErr);
      const margin = qCrit * se;
      pairs.push({
        i,
        j,
        diff,
        se,
        q,
        p,
        lwr: diff - margin,
        upr: diff + margin,
      });
    }
  }
  const result = { pairs, k, df: dfErr, mse };
  if (qCritWarning) result.warning = qCritWarning;
  return result;
}

// Games-Howell — post-hoc for Welch's ANOVA. Uses Welch-Satterthwaite df
// per pair and the studentized range distribution.
//   se_ij = √(s_i²/n_i + s_j²/n_j)
//   q     = (m_i − m_j) / √(se²/2)  … Tukey form, see Day & Quinn 1989
//   df    = (s_i²/n_i + s_j²/n_j)² / ((s_i²/n_i)²/(n_i−1) + (s_j²/n_j)²/(n_j−1))
//   p     = 1 − ptukey(|q|, k, df)
// Returns { pairs: [{ i, j, diff, se, q, df, p }], k }
function gamesHowell(groups) {
  const k = groups.length;
  if (k < 2) return { pairs: [], error: "≥2 groups required" };
  const means = groups.map(sampleMean);
  const vars = groups.map(sampleVariance);
  const ns = groups.map((g) => g.length);
  // Degenerate case: if any group has zero variance, pairs that touch it
  // produce SE=0 (when both sides are zero) or NaN df in the Welch-
  // Satterthwaite formula — ptukey then propagates NaN into p-values.
  // Refuse at the top level rather than return a mix of valid and NaN pairs,
  // which would quietly corrupt compact-letter displays downstream.
  if (vars.some((v) => v === 0)) {
    return {
      pairs: [],
      k,
      error: "Cannot compute Games-Howell — at least one group has zero variance",
    };
  }
  const pairs = [];
  for (let i = 0; i < k - 1; i++) {
    for (let j = i + 1; j < k; j++) {
      const vi = vars[i] / ns[i];
      const vj = vars[j] / ns[j];
      const se = Math.sqrt(vi + vj);
      const diff = means[j] - means[i];
      // Tukey-form q using SE/√2 (consistent with TukeyHSD's SE convention).
      const q = Math.abs(diff) / (se / Math.SQRT2);
      const num = (vi + vj) * (vi + vj);
      const den = (vi * vi) / (ns[i] - 1) + (vj * vj) / (ns[j] - 1);
      const df = num / den;
      const p = ptukey_upper(q, k, df);
      pairs.push({ i, j, diff, se, q, df, p });
    }
  }
  return { pairs, k };
}

// Benjamini-Hochberg adjusted p-values.
// Sort p-values ascending, compute p_(i) · m/i, then enforce monotonicity
// from largest down, and finally cap at 1.
function bhAdjust(ps) {
  const m = ps.length;
  const order = ps.map((p, i) => [p, i]).sort((a, b) => a[0] - b[0]);
  const adj = new Array(m);
  let running = 1;
  for (let rank = m; rank >= 1; rank--) {
    const [p, origIdx] = order[rank - 1];
    const q = (p * m) / rank;
    running = Math.min(running, q);
    adj[origIdx] = Math.min(1, running);
  }
  return adj;
}

// Dunn's test — pairwise rank-based post-hoc following Kruskal-Wallis.
// Uses the *global* rank sums with midranks and tie correction (Siegel
// & Castellan 1988). Z-statistic, two-sided normal p-values, BH-adjusted.
//
//   z_ij = (R_i/n_i − R_j/n_j) / √(σ² · (1/n_i + 1/n_j))
//   σ²   = (N(N+1)/12 − Σ(t³−t)/(12(N−1)))
//   p    = 2 · (1 − Φ(|z|))
// Returns { pairs: [{ i, j, z, p, pAdj }], method }
function dunnTest(groups) {
  const k = groups.length;
  if (k < 2) return { pairs: [], error: "≥2 groups required" };
  const all = [];
  const owner = [];
  for (let i = 0; i < k; i++) {
    for (const v of groups[i]) {
      all.push(v);
      owner.push(i);
    }
  }
  const N = all.length;
  const { ranks, tieCorrection } = rankWithTies(all);
  const meanR = new Array(k).fill(0);
  const ns = groups.map((g) => g.length);
  const sumR = new Array(k).fill(0);
  for (let idx = 0; idx < N; idx++) sumR[owner[idx]] += ranks[idx];
  for (let i = 0; i < k; i++) meanR[i] = sumR[i] / ns[i];
  // Tie-corrected variance term (Dunn 1964 with Siegel-Castellan fix):
  //   σ² = (N(N+1)/12 − (Σ(t³−t)) / (12·(N−1)))
  const sigma2 = (N * (N + 1)) / 12 - tieCorrection / (12 * (N - 1));
  const rawPs = [];
  const pairs = [];
  for (let i = 0; i < k - 1; i++) {
    for (let j = i + 1; j < k; j++) {
      const se = Math.sqrt(sigma2 * (1 / ns[i] + 1 / ns[j]));
      const z = (meanR[i] - meanR[j]) / se;
      const p = 2 * normsf(Math.abs(z));
      pairs.push({ i, j, z, p });
      rawPs.push(p);
    }
  }
  const adj = bhAdjust(rawPs);
  for (let i = 0; i < pairs.length; i++) pairs[i].pAdj = adj[i];
  return { pairs, method: "Benjamini-Hochberg" };
}

// ── 12. Compact letter display ──────────────────────────────────────────────
//
// Piepho 2004 "An Algorithm for a Letter-Based Representation of
// All-Pairwise Comparisons". Given pairwise significance (p < α), assign
// letters to groups such that any two groups sharing at least one letter
// are NOT significantly different.
//
// Input:  pairs = [{ i, j, p }], k groups total, alpha
// Output: array of k strings — each group's letter label, e.g. ["a", "ab", "b"]
//
// Algorithm (insert-and-absorb):
//  1. Start with one letter containing all groups.
//  2. For every significant pair (i, j): split any letter containing both
//     i and j into two letters — one drops i, the other drops j.
//  3. Remove any letter that is a subset of another (absorb).
//  4. Letters are labeled "a", "b", "c"... by order of first appearance.
function compactLetterDisplay(pairs, k, alpha = 0.05) {
  if (k <= 0) return [];
  // Sets of groups, each set = one letter.
  let letters = [new Set(Array.from({ length: k }, (_, i) => i))];
  for (const pr of pairs) {
    const p = pr.pAdj != null ? pr.pAdj : pr.p;
    // Guard NaN explicitly: `NaN >= alpha` is false, so without this the loop
    // would treat any unresolved pair as "significant" and start splitting
    // letters on noise — corrupting the entire CLD silently. NaN p-values
    // arise when an upstream test (tTest, Tukey, etc.) returns an error; we
    // skip them rather than guess, matching R's multcompView::multcompLetters
    // which also requires non-NA inputs.
    if (!Number.isFinite(p) || p >= alpha) continue;
    const { i, j } = pr;
    const newLetters = [];
    for (const L of letters) {
      if (L.has(i) && L.has(j)) {
        const L1 = new Set(L);
        L1.delete(i);
        const L2 = new Set(L);
        L2.delete(j);
        if (L1.size > 0) newLetters.push(L1);
        if (L2.size > 0) newLetters.push(L2);
      } else {
        newLetters.push(L);
      }
    }
    // Absorb: drop any letter that is a strict subset of another.
    const filtered = [];
    for (const L of newLetters) {
      let absorbed = false;
      for (const M of newLetters) {
        if (L === M) continue;
        if (L.size < M.size) {
          let sub = true;
          for (const v of L) {
            if (!M.has(v)) {
              sub = false;
              break;
            }
          }
          if (sub) {
            absorbed = true;
            break;
          }
        }
      }
      if (!absorbed && !filtered.some((F) => F.size === L.size && [...F].every((v) => L.has(v)))) {
        filtered.push(L);
      }
    }
    letters = filtered;
  }
  // Assign labels in order of first group-index each letter contains.
  letters.sort((A, B) => Math.min(...A) - Math.min(...B));
  const labels = "abcdefghijklmnopqrstuvwxyz";
  const out = Array.from({ length: k }, () => "");
  for (let li = 0; li < letters.length; li++) {
    const lbl = labels[li] || `[${li}]`;
    for (const g of letters[li]) out[g] += lbl;
  }
  return out;
}

// ── 13. Automatic test selection ────────────────────────────────────────────
//
// Picks a default test for the user (overridable from the stats panel) and
// returns the full diagnostic trace so they can see *why*.
//
// Default policy — Welch by default:
//
//   k = 2  → Welch's t                      (no post-hoc)
//   k ≥ 3  → Welch's ANOVA + Games-Howell
//
// Welch is unconditional. Shapiro-Wilk and Levene are still computed and
// surfaced in the trace as **diagnostics** — they no longer gate the test
// choice. When SW flags one or more groups as non-normal we add a
// `suggestion` ("consider Mann-Whitney / Kruskal-Wallis"), but the
// recommendation itself stays Welch.
//
// Why Welch by default (and why we *don't* pre-screen with Shapiro):
//
//   1. Pre-testing for normality with SW and routing on the result is a
//      known anti-pattern. Schucany & Ng (2006), Rasch et al. (2011),
//      Zimmerman (2004) all show that the conditional procedure
//      (SW → t / MWU) inflates Type I error and reduces power compared to
//      using Welch's t unconditionally. The original review of this code
//      (1.2.0_harsh_review.md §1.1) flagged this exact issue.
//   2. Welch's t / Welch ANOVA *is* the equal-variance procedure when
//      variances really are equal — the conservative bias is small. When
//      variances differ it is strictly better than Student / one-way
//      ANOVA. Defaulting to it is a free improvement on the equal-variance
//      case and a real improvement on the unequal-variance case.
//   3. Per-group Shapiro at α = 0.05 inflates the family-wise FPR to
//      ~1 − (1 − α)^k (~23 % at k = 5 with everything genuinely normal).
//      Removing it from the gate eliminates that bias entirely.
//
// Why we still compute SW + Levene at all:
//
//   • The decision trace shows them so the user can see the data shape.
//   • For genuinely heavy-tailed data, the user has a real reason to switch
//     to Mann-Whitney / Kruskal-Wallis. We surface that as a *suggestion*
//     (`suggestion.test = "mannWhitney" | "kruskalWallis"`) rather than
//     forcing it — they override from the stats panel's per-test dropdown.
//   • The α = 0.05 / α = 0.05 thresholds are still tuneable via
//     `{ alphaNormality, alphaVariance }` for callers who want a stricter
//     diagnostic flag, but they no longer change the default test.
//
// Returns: { k, normality, allNormal, levene, recommendation, suggestion? }
//
//   - `recommendation.test`  — the test the auto-pick will run.
//   - `recommendation.reason` — multi-sentence explanation: what was picked,
//                              what the diagnostics found, why Welch is
//                              default, how to override.
//   - `suggestion`           — present only when SW flags non-normal data;
//                              names a non-parametric alternative the user
//                              may want to switch to manually.
function selectTest(groups, opts = {}) {
  const alphaN = opts.alphaNormality != null ? opts.alphaNormality : 0.05;
  const alphaV = opts.alphaVariance != null ? opts.alphaVariance : 0.05;
  const k = groups.length;
  if (k < 2) {
    return { error: "≥2 groups required", k };
  }

  // ── Diagnostics (no longer gates) ──
  const normality = groups.map((g, i) => {
    if (g.length < 3) {
      return { group: i, n: g.length, W: null, p: null, normal: null, note: "n<3" };
    }
    const sw = shapiroWilk(g);
    if (sw.error) {
      return { group: i, n: g.length, W: null, p: null, normal: null, note: sw.error };
    }
    return { group: i, n: g.length, W: sw.W, p: sw.p, normal: sw.p >= alphaN };
  });
  const allKnownNormal = normality.every((r) => r.normal === true);
  const flagged = normality.filter((r) => r.normal === false);
  const anyFlagged = flagged.length > 0;

  const lev = leveneTest(groups);
  const equalVar = lev.error ? null : lev.p >= alphaV;

  // ── Default pick: Welch unconditionally ──
  const test = k === 2 ? "welchT" : "welchANOVA";
  const postHoc = k === 2 ? null : "gamesHowell";

  // ── Reason text — explain the policy and the diagnostics ──
  const baseDefault =
    k === 2
      ? "Default pick: Welch's t-test. Welch's t is the recommended default for two independent groups (Rasch, Kubinger & Moder 2011; Zimmerman 2004) — it does not assume equal variances and matches Student's t closely when variances are in fact equal."
      : "Default pick: Welch's ANOVA with Games-Howell post-hoc. Welch's ANOVA is the recommended default for k ≥ 3 independent groups (Delacre et al. 2019; Rasch et al. 2011) — it does not assume equal variances across groups and matches one-way ANOVA closely when variances are in fact equal.";

  // Brief diagnostic narrative — what SW + Levene actually say on this data.
  const swNarrative = (() => {
    if (flagged.length === 0 && allKnownNormal) {
      return "Shapiro-Wilk did not reject normality in any group at α = " + alphaN + ".";
    }
    if (flagged.length > 0) {
      const labels = flagged
        .map((r) => `group ${r.group + 1} (W=${r.W.toFixed(3)}, p=${formatP(r.p)})`)
        .join(", ");
      return `Shapiro-Wilk flagged ${flagged.length} of ${k} group(s) as non-normal at α = ${alphaN}: ${labels}.`;
    }
    // No flagged normal=false but at least one normal=null (n<3 or SW couldn't run).
    return "Shapiro-Wilk could not run on every group (n < 3 in at least one).";
  })();

  const levNarrative = lev.error
    ? `Levene (Brown-Forsythe) could not run: ${lev.error}.`
    : equalVar === false
      ? `Levene (Brown-Forsythe) rejected equal variances (F=${lev.F.toFixed(3)}, p=${formatP(lev.p)}); Welch handles this without further intervention.`
      : `Levene (Brown-Forsythe) did not reject equal variances (F=${lev.F.toFixed(3)}, p=${formatP(lev.p)}); Welch is still the safe default and matches the equal-variance test closely here.`;

  // Optional non-parametric suggestion when SW flags real non-normality.
  let suggestion = null;
  let suggestionNarrative = "";
  if (anyFlagged) {
    suggestion = {
      test: k === 2 ? "mannWhitney" : "kruskalWallis",
      postHoc: k === 2 ? null : "dunn",
      reason:
        "Shapiro-Wilk flagged at least one group as non-normal. Plöttr keeps Welch as the default (pre-screening with SW is a known anti-pattern) but a rank-based test may be more appropriate for genuinely heavy-tailed data.",
    };
    suggestionNarrative = ` If the non-normality looks substantive (heavy tails, strong skew, ordinal data), consider switching to ${suggestion.test === "mannWhitney" ? "Mann-Whitney U" : "Kruskal-Wallis + Dunn (BH)"} from the test dropdown.`;
  }

  const overrideHint =
    " You can override this pick from the stats panel's per-test dropdown; the trace below shows the diagnostics the recommendation is based on.";

  const reason = `${baseDefault} ${swNarrative} ${levNarrative}${suggestionNarrative}${overrideHint}`;

  const out = {
    k,
    normality,
    allNormal: allKnownNormal,
    levene: lev.error
      ? { error: lev.error }
      : { F: lev.F, df1: lev.df1, df2: lev.df2, p: lev.p, equalVar },
    recommendation: { test, postHoc, reason },
  };
  if (suggestion) out.suggestion = suggestion;
  return out;
}

// Map a p-value to the 4-level significance stars used on plots.
// Non-finite or missing p → empty string so callers can suppress the label.
function pStars(p) {
  if (!Number.isFinite(p)) return "";
  if (p < 0.0001) return "****";
  if (p < 0.001) return "***";
  if (p < 0.01) return "**";
  if (p < 0.05) return "*";
  return "ns";
}

// Format a p-value for display next to a test statistic. Uses scientific
// notation below 1e-3 (where fixed-point would round to 0) and keeps 3
// significant digits otherwise.
function formatP(p) {
  if (p == null || !Number.isFinite(p)) return "—";
  if (p < 1e-4) return p.toExponential(1);
  if (p < 1e-3) return p.toExponential(2);
  return p.toFixed(4);
}

// ──────────────────────────────────────────────────────────────────
// stats-cluster.js
// ──────────────────────────────────────────────────────────────────
// stats-cluster.js — distance metrics, hierarchical clustering (`hclust` /
// `dendrogramLayout`), and k-means primitives used by tools/heatmap/.
//
// No dependencies on the other stats-*.js files — distance + clustering use
// only built-ins. Lives alongside stats-*.js by historical accident; the
// "stats" naming is preserved so existing imports keep working through the
// shared bundle.

// ── 14. Hierarchical clustering ─────────────────────────────────────────────

// Pairwise row-wise distance matrix for a 2-D numeric array.
// metric: "euclidean" | "manhattan" | "correlation" (1 − Pearson r).
// NaN cells are ignored pairwise (only rows' shared finite columns contribute).
// Returns an N×N symmetric array of distances (0 on the diagonal).
function pairwiseDistance(matrix, metric) {
  const n = matrix.length;
  const D = Array.from({ length: n }, () => new Array(n).fill(0));
  for (let i = 0; i < n; i++) {
    for (let j = i + 1; j < n; j++) {
      const d = rowDistance(matrix[i], matrix[j], metric);
      D[i][j] = d;
      D[j][i] = d;
    }
  }
  return D;
}

function rowDistance(a, b, metric) {
  const n = Math.min(a.length, b.length);
  const xs = [];
  const ys = [];
  for (let k = 0; k < n; k++) {
    if (Number.isFinite(a[k]) && Number.isFinite(b[k])) {
      xs.push(a[k]);
      ys.push(b[k]);
    }
  }
  if (xs.length === 0) return NaN;
  if (metric === "manhattan") {
    let s = 0;
    for (let k = 0; k < xs.length; k++) s += Math.abs(xs[k] - ys[k]);
    return s;
  }
  if (metric === "correlation") {
    // 1 − Pearson correlation; collapses to 0 for identical vectors,
    // 2 for perfectly anti-correlated ones.
    if (xs.length < 2) return NaN;
    let mx = 0,
      my = 0;
    for (let k = 0; k < xs.length; k++) {
      mx += xs[k];
      my += ys[k];
    }
    mx /= xs.length;
    my /= xs.length;
    let sxy = 0,
      sxx = 0,
      syy = 0;
    for (let k = 0; k < xs.length; k++) {
      const dx = xs[k] - mx;
      const dy = ys[k] - my;
      sxy += dx * dy;
      sxx += dx * dx;
      syy += dy * dy;
    }
    if (sxx === 0 || syy === 0) return 1;
    return 1 - sxy / Math.sqrt(sxx * syy);
  }
  // euclidean (default)
  let s = 0;
  for (let k = 0; k < xs.length; k++) {
    const d = xs[k] - ys[k];
    s += d * d;
  }
  return Math.sqrt(s);
}

// Agglomerative hierarchical clustering. Naive O(n³) merge loop — clear,
// easy to verify, adequate for the ≤500-leaf range the heatmap tool targets.
// linkage: "average" (UPGMA) | "complete" | "single".
// Returns { tree, order }:
//   tree — nested { index, left, right, height, size }; leaves have index ≥ 0
//          and left/right null; internal nodes have index = -1.
//   order — array of leaf indices in dendrogram left-to-right order.
function hclust(distMatrix, linkage) {
  const n = distMatrix.length;
  // Stryker disable next-line all -- defensive early return for empty distance matrix; the algorithm body returns the same shape via { tree: undefined, order: [] }, so most mutations on this guard are equivalent
  if (n === 0) return { tree: null, order: [] };
  // Stryker disable all -- defensive early return for singleton matrix; the while-loop body skips when active.size === 1, so a missed n===1 short-circuit yields the same singleton tree
  if (n === 1)
    return { tree: { index: 0, left: null, right: null, height: 0, size: 1 }, order: [0] };
  // Stryker restore all

  // Working copies: active cluster metadata + mutable distance matrix.
  const clusters = new Array(n);
  const D = new Array(n);
  for (let i = 0; i < n; i++) {
    clusters[i] = { index: i, left: null, right: null, height: 0, size: 1 };
    D[i] = distMatrix[i].slice();
  }
  const active = new Set();
  for (let i = 0; i < n; i++) active.add(i);

  const mergeFn =
    linkage === "complete"
      ? (d1, d2) => Math.max(d1, d2)
      : linkage === "single"
        ? (d1, d2) => Math.min(d1, d2)
        : null; // signals UPGMA (size-weighted average)

  while (active.size > 1) {
    // Find the closest pair among active clusters.
    let best = Infinity;
    let bi = -1,
      bj = -1;
    const act = Array.from(active);
    for (let ai = 0; ai < act.length; ai++) {
      for (let aj = ai + 1; aj < act.length; aj++) {
        const i = act[ai],
          j = act[aj];
        const d = D[i][j];
        if (Number.isFinite(d) && d < best) {
          best = d;
          bi = i;
          bj = j;
        }
      }
    }
    if (bi < 0) {
      // No finite distances remain — happens when rows have no overlap
      // in finite values (e.g. correlation on a matrix where most cells
      // are NaN). Force-merge the two lowest-index active clusters at a
      // sentinel height so the returned tree still covers every leaf,
      // instead of silently truncating to the first active singleton.
      bi = act[0];
      bj = act[1];
      best = 0;
    }

    // Merge j into i — the new cluster keeps index bi, bj becomes inactive.
    const merged = {
      index: -1,
      left: clusters[bi],
      right: clusters[bj],
      height: best,
      size: clusters[bi].size + clusters[bj].size,
    };
    const sizeI = clusters[bi].size;
    const sizeJ = clusters[bj].size;

    active.delete(bj);
    for (const k of active) {
      if (k === bi) continue;
      const dik = D[bi][k];
      const djk = D[bj][k];
      let nd;
      if (mergeFn) {
        nd = mergeFn(dik, djk);
      } else {
        // UPGMA: weighted average by cluster size.
        nd = (sizeI * dik + sizeJ * djk) / (sizeI + sizeJ);
      }
      D[bi][k] = nd;
      D[k][bi] = nd;
    }
    clusters[bi] = merged;
  }

  const rootId = Array.from(active)[0];
  const tree = clusters[rootId];

  // Leaf order by in-order traversal.
  const order = [];
  (function walk(node) {
    if (!node) return;
    if (node.left === null && node.right === null) {
      order.push(node.index);
    } else {
      walk(node.left);
      walk(node.right);
    }
  })(tree);

  return { tree, order };
}

// Flatten a hclust tree into SVG-friendly L-shaped segments.
// Each leaf is placed at integer x = position-in-order; internal nodes
// at the mean of their subtree leaves' positions. Returns:
//   { segments, maxHeight }
// where segments is an array of { x1, y1, x2, y2 } in DATA space
// (y = merge height, 0 at leaves). The caller scales x, y into pixels.
function dendrogramLayout(tree) {
  // Stryker disable next-line all -- defensive early return for null tree (passed when hclust got an empty matrix); the body would crash on null without this guard
  if (!tree) return { segments: [], maxHeight: 0 };
  const segments = [];
  let maxHeight = 0;
  function place(node) {
    if (node.left === null && node.right === null) {
      return { x: node._leafPos, h: 0 };
    }
    const L = place(node.left);
    const R = place(node.right);
    const h = node.height;
    if (h > maxHeight) maxHeight = h;
    // Vertical stems from each child up to the merge height.
    segments.push({ x1: L.x, y1: L.h, x2: L.x, y2: h });
    segments.push({ x1: R.x, y1: R.h, x2: R.x, y2: h });
    // Horizontal bar joining them.
    segments.push({ x1: L.x, y1: h, x2: R.x, y2: h });
    return { x: (L.x + R.x) / 2, h };
  }
  // Annotate leaves with their left-to-right position.
  let leafIdx = 0;
  (function num(node) {
    if (!node) return;
    if (node.left === null && node.right === null) {
      node._leafPos = leafIdx++;
    } else {
      num(node.left);
      num(node.right);
    }
  })(tree);
  place(tree);
  return { segments, maxHeight };
}

// ── 15. K-means (non-hierarchical) clustering ───────────────────────────────

// K-means with k-means++ seeded init. Rows of `matrix` are the observations;
// columns are features. Missing values (NaN) are handled pairwise per-feature
// when computing squared distances, and are skipped when averaging centroids.
// opts: { seed=1, maxIter=100, restarts=8 } — `restarts` independent runs
// from different seeded inits; the lowest-inertia run is returned.
// Returns { clusters, centroids, inertia, iterations, order }:
//   clusters   — array of length n with cluster id (0..k-1) per row
//   centroids  — k × d array (NaN if a feature had no finite values in a cluster)
//   inertia    — sum of squared distances from each row to its centroid
//   iterations — iterations the winning restart took to converge
//   order      — row-index permutation: rows grouped by cluster id, within each
//                cluster sorted by distance-to-centroid ascending. Clusters
//                themselves are ordered by cluster-id.
function kmeans(matrix, k, opts) {
  const options = opts || {};
  const seed = options.seed != null ? options.seed : 1;
  const maxIter = options.maxIter != null ? options.maxIter : 100;
  const restarts = options.restarts != null ? options.restarts : 8;
  const n = matrix.length;
  // Stryker disable next-line all -- defensive early return for empty matrix; the body would crash on `matrix[0].length` (next line) without this guard
  if (n === 0) return { clusters: [], centroids: [], inertia: 0, iterations: 0, order: [] };
  const d = matrix[0].length;
  const kEff = Math.max(1, Math.min(k, n));

  const baseRng = kmeansRng(seed);
  let best = null;
  for (let r = 0; r < restarts; r++) {
    const rng = kmeansRng(Math.floor(baseRng() * 2147483646) + 1);
    const attempt = kmeansOnce(matrix, kEff, d, rng, maxIter);
    if (!best || attempt.inertia < best.inertia) best = attempt;
  }

  // Within-cluster ordering by distance to centroid (ascending).
  const distToCentroid = new Array(n);
  for (let i = 0; i < n; i++) {
    distToCentroid[i] = sqDistPartial(matrix[i], best.centroids[best.clusters[i]]);
  }
  const order = [];
  for (let c = 0; c < kEff; c++) {
    const members = [];
    for (let i = 0; i < n; i++) if (best.clusters[i] === c) members.push(i);
    members.sort((a, b) => distToCentroid[a] - distToCentroid[b]);
    for (const m of members) order.push(m);
  }

  return {
    clusters: best.clusters,
    centroids: best.centroids,
    inertia: best.inertia,
    iterations: best.iterations,
    order,
  };
}

function kmeansOnce(matrix, k, d, rng, maxIter) {
  const n = matrix.length;
  const centroids = kmeansPlusPlusInit(matrix, k, rng);
  const clusters = new Array(n).fill(0);

  let iterations = 0;
  for (let iter = 0; iter < maxIter; iter++) {
    iterations = iter + 1;
    let changed = false;
    for (let i = 0; i < n; i++) {
      let best = 0;
      let bestD = sqDistPartial(matrix[i], centroids[0]);
      for (let c = 1; c < k; c++) {
        const dist = sqDistPartial(matrix[i], centroids[c]);
        if (dist < bestD) {
          bestD = dist;
          best = c;
        }
      }
      if (clusters[i] !== best) {
        clusters[i] = best;
        changed = true;
      }
    }

    // Recompute centroids as per-feature means over finite values.
    const sums = Array.from({ length: k }, () => new Array(d).fill(0));
    const counts = Array.from({ length: k }, () => new Array(d).fill(0));
    const clusterSizes = new Array(k).fill(0);
    for (let i = 0; i < n; i++) {
      const c = clusters[i];
      clusterSizes[c]++;
      for (let j = 0; j < d; j++) {
        const v = matrix[i][j];
        if (Number.isFinite(v)) {
          sums[c][j] += v;
          counts[c][j]++;
        }
      }
    }
    for (let c = 0; c < k; c++) {
      if (clusterSizes[c] === 0) {
        // Empty cluster: reseed to the row farthest from its current centroid.
        let worst = -1;
        let worstD = -Infinity;
        for (let i = 0; i < n; i++) {
          const dist = sqDistPartial(matrix[i], centroids[clusters[i]]);
          if (dist > worstD) {
            worstD = dist;
            worst = i;
          }
        }
        if (worst >= 0) {
          for (let j = 0; j < d; j++) centroids[c][j] = matrix[worst][j];
          clusters[worst] = c;
          changed = true;
        }
        continue;
      }
      for (let j = 0; j < d; j++) {
        centroids[c][j] = counts[c][j] > 0 ? sums[c][j] / counts[c][j] : NaN;
      }
    }
    if (!changed) break;
  }

  let inertia = 0;
  for (let i = 0; i < n; i++) inertia += sqDistPartial(matrix[i], centroids[clusters[i]]);

  return { clusters, centroids, inertia, iterations };
}

function kmeansPlusPlusInit(matrix, k, rng) {
  const n = matrix.length;
  const d = matrix[0].length;
  const centroids = [];
  const first = Math.floor(rng() * n);
  centroids.push(matrix[first].slice());

  const dists = new Array(n).fill(Infinity);
  for (let c = 1; c < k; c++) {
    let total = 0;
    for (let i = 0; i < n; i++) {
      const dist = sqDistPartial(matrix[i], centroids[c - 1]);
      if (dist < dists[i]) dists[i] = dist;
      if (Number.isFinite(dists[i])) total += dists[i];
    }
    if (total <= 0 || !Number.isFinite(total)) {
      // Degenerate: fall back to a random distinct-ish row.
      let pick = Math.floor(rng() * n);
      centroids.push(matrix[pick].slice());
      continue;
    }
    let target = rng() * total;
    let pick = 0;
    for (let i = 0; i < n; i++) {
      if (!Number.isFinite(dists[i])) continue;
      target -= dists[i];
      if (target <= 0) {
        pick = i;
        break;
      }
      pick = i;
    }
    centroids.push(matrix[pick].slice());
  }
  // Ensure every centroid has length d (for rows that had trailing NaN columns).
  for (const c of centroids) {
    while (c.length < d) c.push(NaN);
  }
  return centroids;
}

// Park-Miller LCG — kept local so stats.js has no cross-file dependency.
function kmeansRng(seed) {
  let s = seed % 2147483647;
  if (s <= 0) s += 2147483646;
  return () => {
    s = (s * 16807) % 2147483647;
    return s / 2147483647;
  };
}

function sqDistPartial(row, centroid) {
  const n = Math.min(row.length, centroid.length);
  let s = 0;
  let any = false;
  for (let k = 0; k < n; k++) {
    const a = row[k];
    const b = centroid[k];
    if (Number.isFinite(a) && Number.isFinite(b)) {
      const diff = a - b;
      s += diff * diff;
      any = true;
    }
  }
  return any ? s : Infinity;
}

// ──────────────────────────────────────────────────────────────────
// stats-msi.js
// ──────────────────────────────────────────────────────────────────
// stats-msi.js — multi-set intersection probability for the UpSet tool.
//
// Reference: Wang, Zhao, Zhang, & Bhattacharya (2015). "Efficient Test and
// Visualization of Multi-Set Intersections." Scientific Reports 5:16923.
// (R package: SuperExactTest, function `cpsets`.)
//
// Depends on stats-dist.js for `gammaln`, `betai`, and `gammainc`.
//
// Two code paths:
//   - multisetIntersectionPExact   — iterated hypergeometric DP (log-space).
//   - multisetIntersectionPPoisson — large-N Poisson approximation.
//   - multisetIntersectionP        — router: exact when the DP fits a
//                                    ~10 M-op budget, Poisson otherwise.
// Plus an exclusive-cell binomial test (`multisetExclusiveP`) for UpSet
// bar-height significance.

// ── 14. Multi-set intersection test (SuperExactTest-style) ─────────────────
//
// Under the null of k independent uniformly-random subsets S_1 … S_k of a
// universe U (|U| = N), each with fixed size n_i, what is the probability of
// observing an intersection of size ≥ x_obs?
//
// Reference: Wang, Zhao, Zhang, & Bhattacharya (2015). "Efficient Test and
// Visualization of Multi-Set Intersections." Scientific Reports 5:16923.
// (R package: SuperExactTest, function `cpsets`.)
//
// Two code paths:
//
//   `multisetIntersectionPExact` — iterated hypergeometric conditioning.
//     Y_2 = |S_1 ∩ S_2| ~ Hypergeometric(N, n_1, n_2)
//     Y_i | Y_{i-1} ~ Hypergeometric(N, Y_{i-1}, n_i)  for i ≥ 3
//   We maintain the log-probability distribution of Y_i at each step and
//   marginalise via logSumExp. Returns exp(logTail). All combinatorics run in
//   log-space (stats.js has gammaln) so nothing overflows for N up to ~50 k.
//
//   `multisetIntersectionPPoisson` — large-N approximation. When N is big and
//   the expected intersection size λ = Π(n_i)/N^(k-1) is moderate, |∩| is
//   well-approximated by Poisson(λ). The upper tail is the lower regularised
//   incomplete gamma `P(x_obs, λ)` = `gammainc(x_obs, λ)`.
//
//   `multisetIntersectionP` — router. Picks exact when the DP cost k · min(n_i)²
//   fits a ~10 M-op budget; falls back to Poisson otherwise.
//
// Convention: returned p is a strict upper tail P(|∩| ≥ x_obs) — the "is the
// observed overlap surprisingly large?" question. R's `cpsets` with
// `lower.tail=FALSE` uses P(|∩| > x), so benchmark rows pass `x_obs - 1`.

function _logHypergeomPmf(x, N, K, n) {
  // log P(X = x) for X ~ Hypergeometric(N, K, n). Returns -Infinity on an
  // out-of-support argument so logSumExp skips it.
  if (x < 0 || x > K || x > n || n - x > N - K) return -Infinity;
  const logC = (a, b) => gammaln(a + 1) - gammaln(b + 1) - gammaln(a - b + 1);
  return logC(K, x) + logC(N - K, n - x) - logC(N, n);
}

function _logSumExp(a, b) {
  if (!Number.isFinite(a)) return b;
  if (!Number.isFinite(b)) return a;
  const max = a > b ? a : b;
  return max + Math.log(Math.exp(a - max) + Math.exp(b - max));
}

// Internal: full log-probability distribution of |∩ S_i| under the fixed-
// margin null. Factored out of the public `multisetIntersectionPExact` so
// `multisetIntersectionPExactLower` can reuse the DP result instead of
// recomputing it. Returns an array indexed 0 … min(ns); entries outside
// the support are -Infinity.
function _multisetIntersectionLogPmf(ns, N) {
  // Caller has already validated ns.length ≥ 2, N > 0, and 0 ≤ n_i ≤ N.
  // Smallest set first — keeps intermediate Y vectors narrower (Y_i is bounded
  // by min of {Y_{i-1}, n_i}, so sorting ascending shrinks the state space).
  const sorted = [...ns].sort((a, b) => a - b);
  let logP = new Array(sorted[0] + 1);
  for (let y = 0; y <= sorted[0]; y++) {
    logP[y] = _logHypergeomPmf(y, N, sorted[0], sorted[1]);
  }
  for (let i = 2; i < sorted.length; i++) {
    const n_i = sorted[i];
    const prev = logP;
    const currLen = Math.min(prev.length, n_i + 1);
    const curr = new Array(currLen).fill(-Infinity);
    for (let y = 0; y < prev.length; y++) {
      if (!Number.isFinite(prev[y])) continue;
      const zMax = y < n_i ? y : n_i;
      for (let z = 0; z <= zMax; z++) {
        const logHyp = _logHypergeomPmf(z, N, y, n_i);
        if (!Number.isFinite(logHyp)) continue;
        curr[z] = _logSumExp(curr[z], prev[y] + logHyp);
      }
    }
    logP = curr;
  }
  return logP;
}

// Stryker disable all -- pure input validator: when this lets bad inputs
// through, the algorithm body propagates NaN/Infinity through arithmetic
// and the caller still sees NaN, so individual clauses are equivalent
// mutants. The relevant caller-visible behaviour (NaN on bad shape) is
// pinned in tests/stats.property.test.js's "invalid args → NaN" tests.
function _validateMsiArgs(ns, N) {
  if (!Array.isArray(ns) || ns.length < 2) return false;
  if (!Number.isFinite(N) || N <= 0) return false;
  for (const n_i of ns) {
    if (!Number.isFinite(n_i) || n_i < 0 || n_i > N) return false;
  }
  return true;
}
// Stryker restore all

function multisetIntersectionPExact(xObs, ns, N) {
  // Stryker disable next-line all -- defensive validator delegate; equivalent-mutant pattern (bad inputs would NaN through the DP anyway)
  if (!_validateMsiArgs(ns, N)) return NaN;
  if (xObs <= 0) return 1;
  const minN = Math.min(...ns);
  if (xObs > minN) return 0;
  const logP = _multisetIntersectionLogPmf(ns, N);
  // Upper tail: P(|∩| ≥ x_obs).
  let logTail = -Infinity;
  for (let x = xObs; x < logP.length; x++) {
    if (Number.isFinite(logP[x])) logTail = _logSumExp(logTail, logP[x]);
  }
  if (!Number.isFinite(logTail)) return 0;
  return Math.max(0, Math.min(1, Math.exp(logTail)));
}

// Lower-tail companion: P(|∩| ≤ x_obs) — the depletion test. Same DP as
// `multisetIntersectionPExact`, opposite sum direction. Use this when the
// observed overlap is SMALLER than the expected intersection size
// (`multisetIntersectionExpected`) and you want to test under-enrichment.
// ── Exclusive-cell test (UpSet bar height) ────────────────────────────────
//
// The inclusive-intersection primitives above answer "is |∩ S_i| enriched?"
// (SuperExactTest). But what a user reads off an UpSet bar is the EXCLUSIVE
// count: items in every `inside` set AND no `outside` set. Those are
// different quantities, with different expected values.
//
// Under the independence approximation (each item independently falls in
// S_i with probability n_i/N), the exclusive count for a cell defined by
//   inside = {S_i1, …, S_ip},  outside = {S_j1, …, S_jq}
// is Binomial(N, p_M) with
//   p_M = Π_{i∈inside}(n_i/N) · Π_{j∈outside}(1 − n_j/N)
//
// E[x_exc] = N · p_M, and the p-value uses the regularized incomplete beta
// to compute the Binomial tail without building the CDF term-by-term.
//
// Why not the fixed-margin exact here? That's a 2^k multivariate
// hypergeometric — intractable past k ≈ 6 and overkill for the UI case.
// The independence Binomial is what published UpSet-style exclusive-cell
// tests (VennPlex, pybedtools shuffle reference tables) use.

function multisetExclusiveExpected(insideSizes, outsideSizes, N) {
  // Stryker disable next-line all -- defensive validator; bad N collapses the product to NaN/Infinity through arithmetic anyway, equivalent mutants
  if (!Number.isFinite(N) || N <= 0) return NaN;
  let p = 1;
  for (const n_i of insideSizes) {
    // Stryker disable next-line all -- defensive validator (same reasoning as the N guard above)
    if (!Number.isFinite(n_i) || n_i < 0 || n_i > N) return NaN;
    p *= n_i / N;
  }
  for (const n_j of outsideSizes) {
    // Stryker disable next-line all -- defensive validator (same reasoning)
    if (!Number.isFinite(n_j) || n_j < 0 || n_j > N) return NaN;
    p *= 1 - n_j / N;
  }
  return N * p;
}

// Binomial tail via regularized incomplete beta.
//   tail = "upper" → P(X ≥ x) = I_p(x, N − x + 1)
//   tail = "lower" → P(X ≤ x) = I_{1−p}(N − x, x + 1)
function multisetExclusiveP(xObs, insideSizes, outsideSizes, N, opts) {
  // Stryker disable next-line all -- defensive validator; same reasoning as multisetExclusiveExpected
  if (!Number.isFinite(N) || N <= 0) return NaN;
  const Nint = Math.floor(N);
  const expected = multisetExclusiveExpected(insideSizes, outsideSizes, Nint);
  // Stryker disable next-line all -- defensive: expected is NaN exactly when its inputs are bad; this rethrow is redundant with the upstream check inside multisetExclusiveExpected
  if (!Number.isFinite(expected)) return NaN;
  const p = expected / Nint;
  const tail = opts && opts.tail === "lower" ? "lower" : "upper";
  if (tail === "upper") {
    if (xObs <= 0) return 1;
    if (xObs > Nint) return 0;
    if (p <= 0) return 0;
    if (p >= 1) return 1;
    return betai(xObs, Nint - xObs + 1, p);
  }
  if (xObs < 0) return 0;
  if (xObs >= Nint) return 1;
  if (p <= 0) return 1;
  if (p >= 1) return 0;
  return betai(Nint - xObs, xObs + 1, 1 - p);
}

function multisetIntersectionPExactLower(xObs, ns, N) {
  // Stryker disable next-line all -- defensive validator delegate; equivalent-mutant pattern (bad inputs would NaN through the algorithm body anyway)
  if (!_validateMsiArgs(ns, N)) return NaN;
  if (xObs < 0) return 0;
  const minN = Math.min(...ns);
  if (xObs >= minN) return 1;
  const logP = _multisetIntersectionLogPmf(ns, N);
  let logTail = -Infinity;
  for (let x = 0; x <= xObs && x < logP.length; x++) {
    if (Number.isFinite(logP[x])) logTail = _logSumExp(logTail, logP[x]);
  }
  if (!Number.isFinite(logTail)) return 0;
  return Math.max(0, Math.min(1, Math.exp(logTail)));
}

// Expected value of |∩ S_i| under the fixed-margin null: each item
// independently falls in every S_i with marginal probability n_i / N, so the
// expected intersection size is N · Π(n_i / N) = Π(n_i) / N^(k-1). Kept in
// log-space to avoid Π(n_i) overflow for large k or n_i.
function multisetIntersectionExpected(ns, N) {
  // Stryker disable next-line all -- defensive validator (shape check)
  if (!Array.isArray(ns) || ns.length === 0) return NaN;
  // Stryker disable next-line all -- defensive validator (N range check); equivalent-mutant pattern via NaN propagation through Math.log(N)
  if (!Number.isFinite(N) || N <= 0) return NaN;
  let logLambda = 0;
  for (const n_i of ns) {
    // Stryker disable next-line all -- defensive validator; same reasoning
    if (!Number.isFinite(n_i) || n_i < 0 || n_i > N) return NaN;
    if (n_i === 0) return 0;
    logLambda += Math.log(n_i);
  }
  logLambda -= (ns.length - 1) * Math.log(N);
  return Math.exp(logLambda);
}

function multisetIntersectionPPoisson(xObs, ns, N) {
  // Stryker disable next-line all -- defensive validator (shape check); equivalent-mutant pattern, bad inputs would propagate through gammainc as NaN
  if (!Array.isArray(ns) || ns.length < 2) return NaN;
  // Stryker disable next-line all -- defensive validator (N range check); same reasoning
  if (!Number.isFinite(N) || N <= 0) return NaN;
  for (const n_i of ns) {
    // Stryker disable next-line all -- defensive validator; same reasoning
    if (!Number.isFinite(n_i) || n_i < 0 || n_i > N) return NaN;
    if (n_i === 0) return xObs <= 0 ? 1 : 0;
  }
  if (xObs <= 0) return 1;
  // λ = Π(n_i / N) · N = Π(n_i) / N^(k-1). Compute in log-space to stay finite
  // when Π(n_i) overflows double precision (e.g. k=10, n_i=1000).
  let logLambda = 0;
  for (const n_i of ns) logLambda += Math.log(n_i);
  logLambda -= (ns.length - 1) * Math.log(N);
  const lambda = Math.exp(logLambda);
  if (!Number.isFinite(lambda)) return NaN;
  // P(Poisson(λ) ≥ x_obs) = P(x_obs, λ) (lower regularised incomplete gamma).
  return gammainc(xObs, lambda);
}

function multisetIntersectionP(xObs, ns, N) {
  // Stryker disable next-line all -- defensive validator (shape check); the dispatch below to PExact / PPoisson re-validates fully, so this guard is doubly redundant
  if (!Array.isArray(ns) || ns.length < 2) return NaN;
  // Exact DP cost is ~ (k - 1) · min(n_i)² log-sum-exp evaluations. Cap at
  // ~10 M ops so UI round-trips stay sub-second. Beyond that, Poisson is a
  // safe approximation for the regime (large N relative to the n_i).
  const minN = Math.min(...ns);
  const cost = (ns.length - 1) * minN * minN;
  if (cost <= 10_000_000) return multisetIntersectionPExact(xObs, ns, N);
  return multisetIntersectionPPoisson(xObs, ns, N);
}
